window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q03"]=window.__LIBQ["the-gioi-hoan-my"]["q03"]||{};window.__LIBQ["the-gioi-hoan-my"]["q03"]["artifacts"]={"updatedAt":"2026-07-20","count":175,"artifacts":[{"id":"ngan-dao-thu","name":"Ngân Đào thụ","aliases":["Ngân Đào"],"category":"linh-khi","categoryLabel":"Linh dược","phamCap":"Chuẩn Thánh dược","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Cây bạc chuẩn Thánh dược Nhóc Tỳ đào từ Bách Đoạn Sơn, đã kết hai quả, sắp tiến hóa thành Thánh dược chân chính.","detail":"Cây bạc to bằng cổ tay, cao nửa thân người, cành lá màu bạc như lửa bạc, đã kết hai quả ngả vàng nhạt. Nhóc Tỳ trồng giữa Thạch thôn, vùi bùn cát vàng kim để nuôi dưỡng; cây có cơ hội tiến hóa thành Thánh dược chân chính.","nguon":["@c0201"]},{"id":"kiem-do-rang-nanh-phi-di","name":"Kiếm đỏ răng nanh Phì Di","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Thanh kiếm màu máu luyện từ răng nanh của Phì Di, sắc nhọn với phù văn cường đại.","detail":"Bảo cụ chiến lợi phẩm của Nhóc Tỳ, luyện từ răng nanh màu máu của Phì Di, sắc nhọn và mang phù văn cường đại; nằm trong hơn mười kiện bảo cụ tặng thôn dân.","nguon":["@c0201"]},{"id":"sung-thu-chan-vo","name":"Sừng thú chấn vỡ","category":"phap-bao","categoryLabel":"Bảo cụ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Sừng thú thổi lên phát tiếng ù ù chấn vỡ thân thể, đoạt từ đệ tử Võ Vương phủ Thạch quốc.","detail":"Bảo cụ Nhóc Tỳ đoạt từ đệ tử Võ Vương phủ Thạch quốc; thổi lên phát ra tiếng ù ù có thể chấn vỡ thân thể đối phương.","nguon":["@c0201"]},{"id":"to-khi-thach-thon","name":"Tổ khí Thạch thôn","category":"phap-bao","categoryLabel":"Bảo cụ","soHuu":["Thạch thôn"],"trangThai":"dang-co","blurb":"Hai kiện pháp bảo cường đại do tổ tiên Thạch thôn truyền lại, chỉ dùng khi gặp đại họa.","detail":"Hai kiện tổ khí là pháp bảo cường đại do tổ tiên Thạch thôn truyền lại, chỉ được đem ra dùng khi thôn gặp đại họa.","nguon":["@c0201"]},{"id":"than-dich-thuan-huyet","name":"Thần dịch thuần huyết","aliases":["Bốn giọt thần dịch"],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Cực phẩm","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Bốn giọt chất lỏng cô đặc luyện từ huyết nhục sinh linh thuần huyết, quý hơn hơn mười con thái cổ di chủng, chuẩn bị cho tẩy lễ của Nhóc Tỳ.","detail":"Do Liễu Thần luyện hóa từ bốn khối huyết nhục sinh linh thuần huyết: giọt màu mặc ngọc (huyết Thôn Thiên Tước), giọt đỏ như huyết (huyết Cùng Kỳ), giọt màu vàng và giọt trắng tinh (sinh linh Nam Vẫn Thần Sơn và Nghi Sơn). Bốn giọt được chứa trong bốn bình ngọc, đánh giá quý hơn cả hơn mười con thái cổ di chủng, dành cho việc tẩy lễ của Nhóc Tỳ mà Liễu Thần từng hứa.","nguon":["@c0202"]},{"id":"bot-xuong-thuan-huyet","name":"Bột xương sinh linh thuần huyết","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Nhị Ngốc Tử"],"trangThai":"dang-co","blurb":"Bột trắng như hoa tuyết do Tiểu Tháp nhả ra, có thể làm thành thuốc, được Nhị Ngốc Tử đánh giá là vô giá.","detail":"Khi Liễu Thần điều khiển Tiểu Tháp nhả huyết nhục, nó đồng thời nhả ra thứ bột trắng như hoa tuyết. Nhị Ngốc Tử nhận ra đây là dược liệu vô giá có thể luyện thành thuốc.","nguon":["@c0202"]},{"id":"binh-ngoc-chua-than-dich","name":"Bình ngọc chứa thần dịch","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Bốn bình ngọc mài dũa từ linh ngọc tốt nhất, dùng để chứa bốn giọt thần dịch thuần huyết.","detail":"Vật chứa được mài dũa từ linh ngọc tốt nhất, dùng để bảo quản bốn giọt thần dịch mà Liễu Thần luyện hóa cho việc tẩy lễ của Nhóc Tỳ.","nguon":["@c0202"]},{"id":"huyet-nhuc-thon-thien-tuoc","name":"Huyết nhục Thôn Thiên Tước","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Liễu Thần"],"trangThai":"da-dung","blurb":"Tảng huyết nhục mấy ngàn cân lóe sáng đen bóng của Thôn Thiên Tước, luyện ra giọt thần dịch màu mặc ngọc.","detail":"Do Tiểu Tháp nhả ra, tảng huyết nhục mấy ngàn cân lóe sáng đen bóng, tỏa chấn động chí cường khiến người kinh sợ. Liễu Thần cắm cành liễu luyện hóa nó thành giọt thần dịch màu mặc ngọc.","nguon":["@c0202"]},{"id":"huyet-nhuc-cung-ky","name":"Huyết nhục Cùng Kỳ","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Liễu Thần"],"trangThai":"da-dung","blurb":"Tảng huyết nhục mấy ngàn cân bắn ra hào quang đỏ thẫm của Cùng Kỳ, luyện ra giọt thần dịch đỏ như huyết.","detail":"Do Tiểu Tháp nhả ra, tảng huyết nhục mấy ngàn cân bắn ra hào quang đỏ thẫm, mang chấn động chí cường kinh người. Liễu Thần luyện hóa nó thành giọt thần dịch đỏ như huyết.","nguon":["@c0202"]},{"id":"dia-hoang-hoa","name":"Địa Hoàng Hỏa","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"khong-ro","blurb":"Ngọn lửa mà Tiểu Tháp từng dẫn dụ ở Bách Đoạn Sơn để rèn luyện và chữa trị thân tháp.","detail":"Được nhắc lại trong lời giải thích về Tiểu Tháp: tại Bách Đoạn Sơn, Tiểu Tháp từng dẫn Địa Hoàng Hỏa rèn luyện thân mình, cho thấy nó đang tự chữa trị và hoàn thiện thân tháp.","nguon":["@c0202"]},{"id":"bao-huyet-thai-co-di-chung","name":"Bảo huyết của thái cổ di chủng","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Thái cổ","soHuu":[],"trangThai":"dang-co","blurb":"Bảo vật huyết mạch của giống loài thái cổ còn sót lại, quý giá ngang nguyên thủy bảo cốt. Được hai lão con hàng nêu làm điều kiện giao dịch tin tức về Hùng Hài Tử.","detail":"Bảo huyết của thái cổ di chủng là loại bảo vật trân quý mà Điểu Gia và Tinh Bích đại gia đòi làm giá đổi tin tức, đặt ngang hàng với nguyên thủy bảo cốt; hai lão yêu cầu trưởng tộc các tộc phải đích thân mang tới giao dịch.","nguon":["@c0203","@c0204"]},{"id":"nguyen-thuy-phu-cot","name":"Nguyên thủy phù cốt","category":"nguyen-lieu","categoryLabel":"Vật phẩm quý","phamCap":"Quý hiếm","soHuu":[],"trangThai":"dang-co","blurb":"Thứ quý hiếm được hai lão già chấp nhận thay bảo huyết để đổi tin tức tung tích Nhóc Tỳ.","detail":"Nguyên thủy phù cốt là vật phẩm quý hiếm mà Tinh Bích đại gia và Điểu Gia chấp nhận thay cho bảo huyết thái cổ di chủng khi ra giá trao đổi tin tức tung tích Nhóc Tỳ tại Sơ Thủy Địa.","nguon":["@c0204"]},{"id":"ly-hoa-than-tam","name":"Ly Hỏa Thần Tàm","cn":"","category":"nguyen-lieu","categoryLabel":"Thái cổ di chủng","phamCap":"Thái cổ di chủng / hung vật","soHuu":["Tứ công tử Thác Bạt Tộc","Nhóc Tỳ"],"trangThai":"Đã bị bóp chết, huyết nhục cất làm bảo dược","blurb":"Con tằm thái cổ di chủng đỏ như ngọc, phun tơ mang Ly Hỏa đốt người thành tro.","detail":"Ly Hỏa Thần Tàm là một con tằm thái cổ di chủng lớn cỡ một thước, toàn thân đỏ sậm gần như trong suốt tựa ngọc, bên ngoài lượn lờ hỏa diễm. Tơ nó nhả ra cứng cỏi khó cắt và mang theo Ly Hỏa có thể thiêu người thành tro. Tứ công tử Thác Bạt Tộc ôm nó, dùng nó phun tơ đan lưới để bắt sống Nhóc Tỳ. Trong trận đối đầu ở Sơ Thủy Địa, Nhóc Tỳ dùng Kim Tuyền Ba Văn Công nuốt sạch Ly Hỏa rồi đoạt lấy con tằm. Thấy không thể thuần phục di chủng này, nó dùng sức bóp chết con tằm rồi cất huyết nhục vào túi làm bảo dược.","nguon":["@c0205"]},{"id":"ly-hoa-tam-ti","name":"Ly Hỏa Tàm Ti","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ (tơ tằm tế luyện)","soHuu":["Tứ công tử Thác Bạt Tộc"],"trangThai":"Đã bị Nhóc Tỳ xé rách","blurb":"Lưới thiên la địa võng dệt từ tơ Ly Hỏa Thần Tàm, được lão tổ Thác Bạt Tộc gia trì phù văn.","detail":"Ly Hỏa Tàm Ti là loại tơ do Ly Hỏa Thần Tàm phun ra, đã trải qua tế luyện của lão tổ Thác Bạt Tộc và được gia trì nhiều phù văn thần bí. Sợi tơ được đan thành một tấm lưới thiên la địa võng cực bền, mang theo Ly Hỏa, dùng để trói buộc và bắt sống đối thủ. Tứ công tử Thác Bạt Tộc giăng lưới này định bắt Nhóc Tỳ, nhưng sau khi Ly Hỏa bị Kim Tuyền Ba Văn Công nuốt sạch, Nhóc Tỳ dùng hai tay xé rách tấm lưới, tơ đứt gãy răng rắc, phô bày thần lực đáng sợ.","nguon":["@c0205"]},{"id":"binh-ngoc-bao-huyet","name":"Bình ngọc bảo huyết","cn":"","category":"nguyen-lieu","categoryLabel":"Vật phẩm","phamCap":"Vật phẩm chứa bảo huyết","soHuu":["Nhóc Tỳ"],"trangThai":"Bị Nhóc Tỳ cướp, bọc trong tấm da thú","blurb":"Đống bình ngọc đựng bảo huyết của thái cổ di chủng mà Nhóc Tỳ cướp được.","detail":"Bình ngọc bảo huyết là những chiếc bình ngọc chứa bảo huyết chiết xuất từ thái cổ di chủng. Trong trận ở Sơ Thủy Địa, Nhóc Tỳ nhanh tay bọc cả một đống bình ngọc bảo huyết vào tấm da thú khoác sau lưng rồi phá vòng vây thoát ra. Chính đống bảo huyết này là nguyên nhân khiến Tinh Bích, Điểu Gia cùng Vũ Tộc và tứ đại gia tộc mắt đỏ lên xông tới truy sát nó.","nguon":["@c0205"]},{"id":"diet-hon-cham","name":"Diệt Hồn Châm","cn":"","category":"khac","categoryLabel":"Ma khí","phamCap":"Ma khí bao hàm sức mạnh trật tự","soHuu":["Nhóc Tỳ","Thác Bạt Tộc"],"trangThai":"dang-co","blurb":"Thần châm đỏ đậm tế luyện tại Hư Thần Giới, giết được cả hư thân lẫn chân thân ở hiện thực; gồm mười hai cây, mỗi cây giết một người thì tiêu tán.","detail":"Ma khí đỏ đậm do Thác Bạt Tộc tung ra, tế luyện tại Hư Thần Giới từ vật liệu đặc biệt bao hàm một phần sức mạnh trật tự. Có thể diệt cả thần thức ở hiện thực khiến chân thân chết. Gồm mười hai cây, mỗi cây giết được một người rồi tiêu tán. Nhóc Tỳ né tránh rồi dùng đỉnh lôi điện tím hút lấy và dùng phù văn mi tâm khống chế, đoạt mất khiến Thác Bạt Tộc và chư giáo không đoạt lại được; Nhóc Tỳ giữ lại để về sau đối phó cao tầng các giáo.","nguon":["@c0206","@c0213"]},{"id":"than-tam-ly-hoa","name":"Thần tằm Ly Hỏa","cn":"","category":"khac","categoryLabel":"Di chủng","phamCap":"Di chủng thượng cổ","soHuu":["Thác Bạt Tộc"],"trangThai":"dang-co","blurb":"Di chủng tìm được từ động thiên phúc địa, bị lão tổ Thác Bạt Tộc thuần phục và luyện ra phù văn từ cơ thể nó.","detail":"Thần tằm Ly Hỏa được Tứ công tử Thác Bạt tộc tìm thấy từ động thiên phúc địa trong Hư Thần Giới. Về sau bị lão tổ trong tộc thuần phục và luyện ra phù văn từ cơ thể nó.","nguon":["@c0206"]},{"id":"vat-than-bi-ky-luc-giet-choc","name":"Vật thần bí phần thưởng kỷ lục","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Một vật được luồng hào quang mông lung từ trời bao quanh, rơi tới gần Nhóc Tỳ sau khi nó lập kỷ lục giết chóc; bản chất chưa rõ.","detail":"Sau khi Nhóc Tỳ lập kỷ lục giết chóc tại Sơ Thủy Địa, một luồng hào quang mông lung từ trên trời giáng xuống bao quanh một thứ và dần dần rơi tới gần nó. Bản chất và công dụng của vật này chưa được tiết lộ.","nguon":["@c0206"]},{"id":"sach-than-thai-co","name":"Sách Thần Thái Cổ","aliases":["Thái Cổ Thần Thư","Sách quý đồng thau","Sách thần đồng thau","mảnh vỡ đồng thau"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Thánh vật Thái Cổ","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Mảnh kim loại đồng thau dị thường cực cứng, là một phần mười của một cuốn sách thần thời Thái Cổ, do pháp tắc trật tự thế giới ban xuống khi Nhóc Tỳ lập kỷ lục.","detail":"Một chùm sáng như đèn lồng giáng xuống rồi nứt ra để lộ mảnh đồng thau cứng đến mức cắn cũng không nát, được xác nhận chiếm một phần mười của sách thần thời Thái Cổ. Nếu gom đủ toàn bộ các mảnh vỡ đồng thau sẽ mở ra một tòa tiên tàng chứa những bảo thuật cái thế của thời đại Thái Cổ, được ví như nguyên thủy phù cốt vô thượng chứa đựng đại thần thông — vật mà cả hung thú thuần huyết lẫn chim thần đều hằng mơ ước. Muốn thu các mảnh còn lại phải tiếp tục phá những kỷ lục gian nan nhất, gần như không thể hoàn thành.","nguon":["@c0207"]},{"id":"thanh-vat-than-bi-nghi-nhi","name":"Thánh vật thần bí của Nghị nhi","category":"khac","categoryLabel":"Khác","phamCap":"Thánh vật (chưa rõ)","soHuu":["Nghị nhi"],"trangThai":"dang-co","blurb":"Báu vật mà Nghị nhi của Vũ Tộc từng nhận được và giấu kín, nghe nói giá trị không kém Sách Thần Thái Cổ.","detail":"Được nhắc tới gián tiếp trong lúc Vũ Tộc bàn tính đối phó Nhóc Tỳ; một thánh vật thần bí giấu kín, chưa lộ hình dạng hay công năng, nghe nói không thua kém Sách Thần Thái Cổ.","nguon":["@c0207"]},{"id":"sach-quy-dong-thau","name":"Sách quý đồng thau","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bí điển thần cấp","soHuu":["Nhóc Tỳ"],"trangThai":"Nhóc Tỳ giữ, chỉ cho hai lão xem một góc vỡ chưa giao hẳn","blurb":"Sách thần bằng đồng thau, chỉ một mảnh nhỏ xuất hiện đã kinh động các lão tổ gia tộc Thượng Cổ.","detail":"Còn gọi là sách thần bằng đồng thau. Khi một mảnh nhỏ của nó lộ ra đã kinh động đến các lão tổ gia tộc Thượng Cổ, khiến bọn họ bàn tán xôn xao. Nhóc Tỳ nắm giữ và dùng nó làm quân bài mặc cả: chỉ cho Tinh Bích đại gia cùng Điểu gia xem một góc vỡ bằng đồng thau nhưng chưa giao hẳn, hé mở khả năng hợp tác về sau quanh bí điển này.","nguon":["@c0208"]},{"id":"bao-huyet-di-chung","name":"Bảo huyết di chủng","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Chưa rõ","soHuu":["Vũ Tộc","Thác Bạt Tộc"],"trangThai":"dang-co","blurb":"Bảo huyết của sinh linh di chủng mà Hùng Hài Tử đòi các gia tộc nộp mười bình mỗi tộc.","detail":"Thứ Hùng Hài Tử ra lệnh mỗi gia tộc, bắt đầu từ Vũ Tộc và Thác Bạt Tộc, phải nộp mười bình trong hạn một canh giờ; nếu không giao nó sẽ tự tới lấy. Đây là một phần hành động báo thù các thế lực từng huyết chiến với Bổ Thiên Các.","nguon":["@c0209"]},{"id":"bao-phien-mau-uyen-toc","name":"Bảo phiến màu máu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo trấn tộc","phamCap":"Bảo vật trấn tộc Uyên Tộc","soHuu":["Nhóc Tỳ"],"trangThai":"dang-co","blurb":"Quạt màu đỏ, bảo vật trấn tộc Uyên Tộc, Nhóc Tỳ đoạt từ tứ đại gia tộc ở Sơ Thủy Địa; vỗ ra hỏa diễm ngập trời.","detail":"Bảo phiến màu máu là chí bảo trấn tộc của Uyên Tộc bị Nhóc Tỳ cướp từ tứ đại gia tộc ở Sơ Thủy Địa. Khi vỗ ra, quạt phun hỏa diễm ngập trời như núi lửa phun trào, thiêu Ngân Thiên Lang thành Hỏa Lang trong trận chiến với Vũ Tộc ở Hư Thần Giới.","nguon":["@c0210"]},{"id":"ngan-thien-lang","name":"Ngân Thiên Lang","cn":"","aliases":["Khuyết Nguyệt Thiên Lang"],"category":"phap-bao","categoryLabel":"Bảo cụ hóa hung thú","phamCap":"Dị chủng Thái Cổ (tấm da)","soHuu":["Vũ Tộc"],"trangThai":"hong","blurb":"Tấm da thú dị chủng Thái Cổ của Vũ Tộc, tế ra hóa thành hung thú cao như núi; bị Nhóc Tỳ đánh gãy xương sống, thiêu cháy còn lại tấm da sói thủng lỗ.","detail":"Vũ Tộc tế ra tấm da thú dị chủng Thái Cổ hóa thành Khuyết Nguyệt Thiên Lang (Ngân Thiên Lang), hung thú cao như núi với đầu sói, sừng, đuôi cá sấu, có cánh và vảy bạc. Nhóc Tỳ dùng bảo phiến máu thiêu nó thành Hỏa Lang rồi dùng quyền tím đánh gãy xương sống, buộc Vũ Tộc thu hồi khi chỉ còn tấm da sói cháy đen thủng lỗ tối đen.","nguon":["@c0210"]},{"id":"phao-dai-bao-cot-vu-toc","name":"Pháo đài bảo cốt Vũ Tộc","cn":"","category":"phap-bao","categoryLabel":"Chí bảo trấn tộc","phamCap":"Báu vật vô giá","soHuu":["Vũ Tộc"],"trangThai":"hong","blurb":"Tòa kiến trúc cổ xưa chứa nhiều bảo cốt, chí bảo trấn tộc của Vũ Tộc; bị kiếm gãy Nhóc Tỳ đánh nổ tung.","detail":"Một tòa pháo đài (kiến trúc cổ) từ dưới đất nhô lên, ẩn chứa nhiều bảo cốt và tỏa ánh sáng giết chóc, là báu vật vô giá được Vũ Tộc tế luyện nhiều năm. Trong trận chiến, Nhóc Tỳ dùng kiếm gãy đánh nổ tung tòa pháo đài, khiến các lão Vũ Tộc phun máu.","nguon":["@c0210"]},{"id":"phap-chi-than-linh","name":"Pháp chỉ của Thần Linh","aliases":["Pháp chỉ chữ Phạt"],"category":"than-khi","categoryLabel":"Di vật thần","phamCap":"Di vật Thần Linh","soHuu":["Vũ Tộc"],"trangThai":"dang-co","blurb":"Tấm pháp chỉ cuối cùng Vũ Thần lưu lại, gồm mười tờ giấy màu vàng đất nát bét ghép lại; ghép đủ mới đại biểu ý chí Thần Linh.","detail":"Pháp chỉ được đựng trong bình đen đặt trên tế đàn trong miếu thần Vũ Tộc, khi mở ra khí tức bùng lên như Thần Linh xuất thế. Mười tờ giấy vàng đất mỗi tờ mang ít chữ viết, ghép đủ mới đại biểu ý chí Thần Linh. Tờ Vũ Tử Mạch chọn ghi chữ “Phạt”, tuy không phải “Giết” nhưng đủ mạnh chém bất kỳ địch thủ nào trong Hư Thần Giới. Pháp chỉ khắc bằng ý chí tinh thần, hơn xa các chí bảo khác và hơn xa tờ giấy không chữ ở Bách Đoạn Sơn (thứ kia chỉ là hư). Khi bộc phát, nó ảnh hưởng cả quy tắc trật tự Hư Thần Giới, trút mưa ánh sáng vàng đánh Nhóc Tỳ đầy lỗ máu.","nguon":["@c0211"]},{"id":"binh-den-phap-chi","name":"Bình đen","category":"khac","categoryLabel":"Vật chứa","phamCap":"Không rõ","soHuu":["Vũ Tộc"],"trangThai":"dang-co","blurb":"Chiếc bình toàn thân đen thui, lấm tấm như giọt mưa, dùng đựng mười tờ pháp chỉ nát của Vũ Thần.","detail":"Bình đen được đặt trên tế đàn nhỏ trước tượng thần trong miếu thần Vũ Tộc. Khi mở ra vọt lên khí tức kinh khủng như Thần Linh xuất thế, bên trong là mười tờ giấy màu vàng đất ghép thành pháp chỉ. Sau khi lấy tờ chữ “Phạt”, các tờ còn lại được đưa lại vào bình, đậy nắp và đặt về tế đàn.","nguon":["@c0211"]},{"id":"binh-bao-huyet-tri-thuong","name":"Bình bảo huyết","category":"dan-duoc","categoryLabel":"Đan dược / Vật phẩm","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"da-dung","blurb":"Bình bảo huyết Nhóc Tỳ dùng để trị thương giữa trận quyết đấu.","detail":"Trong lúc quyết đấu với pháp chỉ Vũ Thần và trọng thương, Nhóc Tỳ lấy ra bình bảo huyết, mở nắp uống ừng ực để trị thương rồi tiếp tục chiến đấu.","nguon":["@c0212"]},{"id":"phap-chi-vu-than-phat","name":"Pháp chỉ Vũ Thần (chữ Phạt)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp chỉ Thần Linh","soHuu":["Vũ Tộc"],"trangThai":"hong","blurb":"Tờ giấy vàng đất mang ý chí Thần Linh chữ “Phạt”, phóng thần uy nhưng cuối cùng vỡ nát và bị Nhóc Tỳ ăn.","detail":"Tờ giấy vàng đất mang ý chí Thần Linh của Vũ Thần, khắc chữ “Phạt”, phóng ra thần uy nhằm tiêu diệt kẻ địch. Bị tiểu tháp va chạm cùng kiếm gãy chém nên không ổn định, cuối cùng vỡ nát chỉ còn lại một tờ giấy bị cắt làm hai nửa và mất ý chí Thần Linh. Nhóc Tỳ nhét cả hai nửa vào miệng nhai nuốt, khiến các lão giả Vũ Tộc hộc máu vì cho là xúc phạm Thần Linh.","nguon":["@c0213"]},{"id":"tran-hon-thap","name":"Trấn Hồn Tháp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vũ Tộc"],"trangThai":"dang-co","blurb":"Công cụ Vũ Tộc dùng để giết hồn phách và luyện hóa, định biến chân thân Nhóc Tỳ thành thân tử đạo tiêu.","detail":"Pháp bảo của Vũ Tộc chuyên giết hồn phách và luyện hóa. Sau khi cấm trận kích nổ khiến Nhóc Tỳ trọng thương, bọn Vũ Tộc định dùng Trấn Hồn Tháp để biến chân thân của nó thành “thân tử đạo tiêu”.","nguon":["@c0213"]},{"id":"than-chu-vu-toc","name":"Thần chu Vũ Tộc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo phi hành","phamCap":"không rõ","soHuu":["Vũ Tộc"],"trangThai":"hong","blurb":"Thần chu Vũ Tộc là chiếc thuyền thần màu xanh da trời, phủ phù văn và có tốc độ cực nhanh. Nó được điều đến chặn đường Nhóc Tỳ khi cậu định rời tịnh thổ để mở Động Thiên thứ mười.","detail":"Chiếc thần chu chở nhiều cao thủ Vũ Tộc vượt lên chặn trước Nhóc Tỳ. Trong cuộc phản công, Nhóc Tỳ triệu Côn Bằng ngậm kiếm gãy chém đứt một khúc thân thuyền, buộc các cao thủ trên thuyền phải bỏ chạy.","nguon":["@c0214"]},{"id":"bao-an-vu-toc","name":"Bảo ấn Vũ Tộc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo trấn áp","phamCap":"không rõ","soHuu":["Vũ Tộc"],"trangThai":"hong","blurb":"Bảo ấn Vũ Tộc là pháp bảo được tế luyện nhiều năm, có thể hóa thành ngọn núi để trấn áp đối thủ. Trong chương 214, nó bị bảo thuật Côn Bằng của Nhóc Tỳ đâm nát thành tro.","detail":"Bảo ấn khi được thả ra hóa thành một ngọn núi có cây cối chim cá, mang uy thế đè ép mạnh mẽ. Nhóc Tỳ dùng Côn Bằng khổng lồ lao thẳng lên trời, phá hủy bảo ấn ngay trong đợt phản kích của Vũ Tộc.","nguon":["@c0214"]},{"id":"phu-tien-vu-toc","name":"Phù tiễn Vũ Tộc","cn":"","aliases":["Mũi tên cốt văn"],"category":"khac","categoryLabel":"Vũ khí cốt văn","phamCap":"không rõ","soHuu":["Vũ Tộc"],"trangThai":"da-dung","blurb":"Phù tiễn Vũ Tộc là hàng vạn mũi tên khắc cốt văn được bắn ra để ngăn Nhóc Tỳ đột phá. Chúng có lực sát thương lớn nhưng bị Toan Nghê tím do lôi điện hóa thành phá tan.","detail":"Trong trận tịnh thổ, Vũ Tộc bắn hàng vạn phù tiễn khắc cốt văn, đủ sức phá thành trì núi non. Nhóc Tỳ triệu Toan Nghê màu tím dựng thế lôi điện, chặn phá toàn bộ làn mưa tên này.","nguon":["@c0214"]},{"id":"mieng-thanh-dong","name":"Miếng thanh đồng","cn":"","aliases":["Miếng đồng thau"],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Chưa rõ","soHuu":["Nhóc Tỳ"],"trangThai":"Nhóc Tỳ đang giữ","blurb":"Miếng thanh đồng là vật quý trên người Nhóc Tỳ bị Thác Bạt Tộc nhắm tới. Nhị công tử Thác Bạt Tộc nhường phần đoạt vật này cho Lục công tử nộp lên tộc.","detail":"Trong cuộc truy sát ở khu rừng Hư Thần Giới, các công tử Thác Bạt nhắc tới miếng thanh đồng trên người Nhóc Tỳ như một chiến lợi phẩm quan trọng. Giá trị và công dụng cụ thể chưa được nói rõ, nhưng đủ khiến người của Thác Bạt Tộc muốn đoạt lấy để dâng lên trong tộc.","nguon":["@c0217"]},{"id":"ma-cham-mau-do-dam","name":"Ma châm màu đỏ đậm","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Ma khí","phamCap":"Chưa rõ","soHuu":["Lục công tử Thác Bạt Tộc"],"trangThai":"Đang sử dụng","blurb":"Ma châm màu đỏ đậm là vũ khí Lục công tử Thác Bạt Tộc lấy ra khi truy sát Nhóc Tỳ. Nó phát ánh sáng lạnh buốt và được dùng với ý đồ tiêu diệt cả hư thân lẫn chân thân.","detail":"Khi cùng Nhị công tử Thác Bạt Tộc cá cược giết Nhóc Tỳ, Lục công tử lấy ra ma châm màu đỏ đậm. Vật này được mô tả là âm độc, nhằm khiến Nhóc Tỳ chết trong Hư Thần Giới và liên lụy tới chân thân.","nguon":["@c0217"]},{"id":"cham-than-mau-do-luc-cong-tu","name":"Châm thần màu đỏ","cn":"","aliases":["Châm thần màu đỏ của Lục công tử"],"category":"phap-bao","categoryLabel":"Châm thần","phamCap":"Không rõ","soHuu":["Lục công tử Thác Bạt Tộc","Nhóc Tỳ"],"trangThai":"bị đoạt","blurb":"Châm thần đỏ đậm trong tay Lục công tử Thác Bạt Tộc. Khi Nhóc Tỳ kéo hắn tới, vật này bị đoạt rồi dùng để đâm vào đầu hắn, khiến thần hồn hủy diệt.","detail":"Chương không nói thẳng châm thần này đồng nhất với Diệt Hồn Châm của Nhị công tử, nên ghi riêng theo mô tả xuất hiện. Nó thể hiện cùng kiểu pháp bảo công kích thần hồn, đủ khiến chân thân liên đới chết theo khi thần hồn bị hủy.","nguon":["@c0218"]},{"id":"ma-khi","name":"Ma khí","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Tứ đại gia tộc Côn, Ly, Mông, Uyên","Nhóc Tỳ"],"trangThai":"bị Nhóc Tỳ cướp sạch khỏi đám đầu lĩnh","blurb":"Vật phẩm đặc biệt do tứ đại gia tộc Côn, Ly, Mông, Uyên mang ra để đối phó Nhóc Tỳ.","detail":"Tứ đại gia tộc nắm giữ ma khí và lấy ra vật quan trọng nhất trong tộc, muốn trả giá lớn để giết cả hư thân lẫn chân thân của Nhóc Tỳ. Khi giao chiến, các đầu lĩnh bị Nhóc Tỳ đánh bại và ma khí bị cướp sạch.","nguon":["@c0219"]},{"id":"to-khi-thac-bat-toc","name":"Tổ Khí Thác Bạt Tộc","cn":"","aliases":["Tổ Khí"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"bảo cụ đặc biệt","soHuu":["Lão tổ Thác Bạt Tộc","Thác Bạt Tộc"],"trangThai":"đang được Thác Bạt Tộc nắm giữ","blurb":"Bảo cụ đặc biệt của Thác Bạt Tộc, có năng lực súc địa thành thốn và có thể mang vào Hư Thần Giới. Lão tổ Thác Bạt Tộc dùng nó để bọc người còn lại chạy thoát khỏi Nhóc Tỳ.","detail":"Sau khi tịnh thổ Thác Bạt Tộc bị đánh tan, lão tổ lấy Tổ Khí quấn quanh nhóm người sống sót, hóa thành một vùng sáng lao tới cuối đại địa và biến mất. Công dụng nổi bật được nêu ở chương này là di chuyển cực nhanh theo kiểu súc địa thành thốn.","nguon":["@c0220"]},{"id":"bao-tay-cua-lao-gia","name":"Bao tay của lão già","cn":"","category":"phap-bao","categoryLabel":"Chí bảo","phamCap":"Binh khí của Thần minh","soHuu":["Lão già tổ phụ của thiếu nữ áo tím"],"trangThai":"đang sử dụng","blurb":"Bao tay của lão già là chí bảo có khí tức thần linh, được chính lão gọi là binh khí của Thần minh. Nó giúp lão chống cự Nhóc Tỳ, đồng thời khiến Nhóc Tỳ nảy ý đoạt lấy.","detail":"Trong trận ở Hư Thần Giới, Nhóc Tỳ nhận ra bao tay của lão già có khí tức thần linh và lập tức đòi lấy. Lão dùng nó để chống đỡ sức công phạt của Nhóc Tỳ, sau đó tiết lộ đây là binh khí của Thần minh nhằm dọa đối phương, nhưng Nhóc Tỳ vẫn không buông ý định đoạt bảo.","nguon":["@c0221"]},{"id":"bong-tai-cua-thieu-nu","name":"Bông tai của thiếu nữ","cn":"","category":"phap-bao","categoryLabel":"Chí bảo phòng ngự","phamCap":"Có sức mạnh của Thần","soHuu":["Thiếu nữ áo tím"],"trangThai":"đang sử dụng","blurb":"Bông tai của thiếu nữ áo tím là chí bảo phòng ngự được chí cường giả tế luyện. Khi vận dụng, nó tạo màn sáng có sức mạnh của Thần chuyển động để ngăn Nhóc Tỳ áp sát.","detail":"Thiếu nữ áo tím lấy bông tai ra trong lúc đối đầu Nhóc Tỳ, dùng sức mạnh được chí cường giả tế luyện để ngăn thế công cận chiến. Nhóc Tỳ vẫn đánh xuyên qua lớp phòng ngự, nhưng cũng nhận xét vật này tốt hơn bảo vật trước đó của nàng.","nguon":["@c0221"]},{"id":"bao-huyet-tu-dai-hung-thu","name":"Bảo huyết tứ đại hung thú","cn":"","category":"dan-duoc","categoryLabel":"Thần dịch tẩy lễ","phamCap":"Chí cường hung thú","soHuu":["Liễu Thần","Thạch Hạo"],"trangThai":"da-dung","blurb":"Bốn giọt thần dịch cô đọng từ bảo huyết của Thôn Thiên Tước, sinh linh Nghi Sơn, Cùng Kỳ và sinh linh Nam Lĩnh Thần Sơn.","detail":"Bảo huyết tứ đại hung thú được Liễu Thần tế luyện, chứa trong bốn bình ngọc và dùng làm nền tảng Cực Cảnh Tẩy Lễ cho Thạch Hạo. Khi bốn bình vỡ, thần dịch nổ tung thành thần uy hủy diệt nhưng được cành liễu thuần hóa thành thác cam lộ trút xuống người hắn.","nguon":["@c0224"]},{"id":"than-tinh-tinh-hoa-cua-lieu-than","name":"Thần tính tinh hoa của Liễu Thần","cn":"","category":"dan-duoc","categoryLabel":"Thần dịch tinh hoa","phamCap":"Thần tính tinh hoa","soHuu":["Liễu Thần","Thạch Hạo"],"trangThai":"da-dung","blurb":"Chất lỏng thần tính nhỏ xuống từ hơn mười cành liễu xanh của Liễu Thần trong lần tẩy lễ.","detail":"Thần tính tinh hoa của Liễu Thần mang sinh mệnh khí cơ mênh mông như biển. Khi được buông xuống, nó khiến thảm thực vật quanh Thạch thôn tươi tốt, cây khô hồi sinh, người bệnh cũ khỏi hẳn và tộc lão cao niên trở nên hồng hào; phần tinh hoa trọng yếu được tưới vào mười Động Thiên của Thạch Hạo để trợ hắn phá cực hạn.","nguon":["@c0224"]},{"id":"bon-binh-ngoc","name":"Bốn bình ngọc","cn":"","category":"khac","categoryLabel":"Vật chứa","phamCap":"Không rõ","soHuu":["Liễu Thần"],"trangThai":"hong","blurb":"Bốn bình ngọc chứa bốn giọt bảo huyết tứ đại hung thú dùng trong Cực Cảnh Tẩy Lễ.","detail":"Khi Liễu Thần tuyên bố bắt đầu tẩy lễ, bốn bình ngọc lập tức vỡ tan, để bốn giọt thần dịch trong suốt bay lên và nổ tung thành luồng thần uy dữ dội.","nguon":["@c0224"]},{"id":"chat-long-cua-lieu-than","name":"Chất lỏng của Liễu thần","aliases":[],"cn":"","category":"nguyen-lieu","categoryLabel":"Tài nguyên tu luyện","phamCap":"Thần tính sinh cơ","soHuu":["Liễu thần","Nhóc Tỳ"],"trangThai":"đã dùng trong tu luyện và chữa thương","blurb":"Dịch thể trong suốt rực rỡ của Liễu thần, được Nhóc Tỳ dùng làm sinh cơ khi diễn biến lại Động Thiên.","detail":"Chất lỏng này được ví như mầm mống sinh mạng, rót vào Động Thiên khiến sinh cơ bừng bừng. Trong quá trình tự hủy và tái tạo Động Thiên, Nhóc Tỳ dựa vào nguồn sinh cơ này để thử diễn biến vạn vật và hỗ trợ chữa thương.","nguon":["@c0225"]},{"id":"than-dich","name":"Thần dịch","cn":"","category":"dan-duoc","categoryLabel":"Thần dịch tu luyện","phamCap":"Không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"đã dùng một phần","blurb":"Chất lỏng óng ánh còn dư được Nhóc Tỳ dùng trong lần tẩy lễ cuối. Thần tính tinh hoa của nó sôi trào khi mười Động Thiên va chạm dữ dội.","detail":"Trong chương 226, Nhóc Tỳ dùng phần thần dịch còn lại để tiến hành lần tẩy lễ và đánh cược cuối cùng ở Động Thiên cảnh. Khi quá trình biến hóa trở nên mãnh liệt, thần tính tinh hoa trong thần dịch sôi trào như đại dương, trợ lực cho mười Động Thiên tương liên hóa thành thần hoàn.","nguon":["@c0226"]},{"id":"bia-ky-luc-dong-thien-chi-ton","name":"Bia Kỷ Lục Động Thiên Chí Tôn","cn":"","category":"khac","categoryLabel":"Bia đá chứng nhận","phamCap":"không rõ","soHuu":["Nhóc Tỳ"],"trangThai":"hiển hiện trong Hư Thần Giới","blurb":"Bia đá hiện ra sau khi Nhóc Tỳ được xác nhận là người mạnh nhất Động Thiên cảnh trong Hư Thần Giới ở Hoang Vực. Trên bia chỉ có bốn chữ Động Thiên Chí Tôn.","detail":"Bia Kỷ Lục Động Thiên Chí Tôn là bia đá lấp lánh văn tự, do Hư Thần Giới dựng lên để chứng nhận thành tựu của Nhóc Tỳ ở Động Thiên cảnh. Nó đánh dấu địa vị chưa ai đột phá được trong thế giới tinh thần tại Hoang Vực vào thời điểm này.","nguon":["@c0228"]},{"id":"ky-luc-bia-thach-nghi","name":"Kỷ lục bia của Thạch Nghị","aliases":["Bia của Thạch Nghị","Kỷ lục bia"],"cn":"","category":"khac","categoryLabel":"Bia kỷ lục","phamCap":"thần thạch thiên thạch","soHuu":["Võ Vương Phủ","Thạch Nghị"],"trangThai":"bị phá nát @c0229","blurb":"Tấm bia kỷ lục đặt tại Diễn Võ Trường Võ Vương Phủ, làm từ thiên thạch vũ trụ và khắc chưởng ấn của Thạch Nghị. Khi Nhóc Tỳ đặt tay lên chưởng ấn, tấm bia nổ tung chia năm xẻ bảy.","detail":"Kỷ lục bia của Thạch Nghị được đặt ở vị trí bắt mắt tại Diễn Võ Trường, chất liệu là thiên thạch vũ trụ, ngưng kết sức mạnh thần bí và vốn được xem là cứng không thể phá. Trên bia có chưởng ấn do Thạch Nghị lưu lại bằng sức mạnh Chí Tôn Cốt, để người cùng thế hệ lĩnh ngộ pháp và đạo; cảm ứng từ xương ngực Nhóc Tỳ khiến nó nổ tung trong thần quang.","nguon":["@c0229"]},{"id":"canh-cay-ong-anh-lieu-than","name":"Cành cây óng ánh của Liễu Thần","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Cành cây dài bằng lòng bàn tay, óng ánh, do Liễu Thần trao cho Thạch Hạo để triệu cứu viện.","detail":"Liễu Thần trao cho Thạch Hạo một cành cây dài bằng lòng bàn tay, óng ánh; khi cần thiết Liễu Thần sẽ chạy tới cứu viện thông qua vật này.","nguon":["@c0231"]},{"id":"cay-dao-bac","name":"Cây đào bạc","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Gần thánh dược","soHuu":[],"trangThai":"dang-co","blurb":"Cây đào bạc trồng ở Thạch Thôn, gần đạt tới thánh dược, tỏa linh khí lớn.","detail":"Trồng ở Thạch Thôn, sau mấy tháng biến hóa lớn cùng các linh dược khác, cây đào bạc gần đạt tới thánh dược và tỏa ra linh khí dồi dào.","nguon":["@c0231"]},{"id":"trung-than-bat-tran-ke","name":"Trứng thần của Bát Trân Kê","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Bảo dược","soHuu":[],"trangThai":"dang-co","blurb":"Trứng thần do con Bát Trân Kê sống gần Liễu Thần đẻ ra, là bảo dược duy trì lâu dài.","detail":"Con Bát Trân Kê sinh sống gần Liễu Thần trong Thạch Thôn bắt đầu đẻ trứng thần, một loại bảo dược có tác dụng nuôi dưỡng lâu dài.","nguon":["@c0231"]},{"id":"chuan-thanh-duoc","name":"Chuẩn Thánh Dược","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Chuẩn Thánh","soHuu":["Thạch Thôn"],"trangThai":"dang-co","blurb":"Linh dược quý trong Thạch Thôn, nay đã ra hoa kết quả, bên cạnh mấy chục gốc linh dược khác.","detail":"Trong lúc tộc nhân tiễn biệt Thạch Hạo, họ cho biết Thạch Thôn nay không thiếu gì: có mấy chục gốc linh dược, Chuẩn Thánh Dược đã ra hoa kết quả, lại còn có Bát Trân Kê.","nguon":["@c0232"]},{"id":"bao-thuat-con-bang","name":"Bảo thuật Côn Bằng","cn":"","category":"khac","categoryLabel":"Bảo thuật","phamCap":"Đại thần thông Thái Cổ","soHuu":[],"trangThai":"dang-co","blurb":"Đại thần thông của thập hung Thái Cổ Côn Bằng, mục tiêu mà liên minh các thế lực muốn đoạt được ở Hải Vực.","detail":"Bảo thuật của thập hung Thái Cổ Côn Bằng, cất giấu ở hang ổ/thần sào Côn Bằng trong Hải Vực. Nhiều thế lực lớn liên hợp thành liên minh, tập hợp các thiếu niên nam nữ Hóa Linh Cảnh làm chủ lực, cùng nhau ra biển với hi vọng đoạt được bảo thuật này.","nguon":["@c0233"]},{"id":"linh-duoc-khe-nui","name":"Linh dược khe núi","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Mao Cầu"],"trangThai":"da-dung","blurb":"Cây linh dược mọc từ khe núi trên Thiên Thần Sơn mà Nhóc Tỳ ngắt cho Mao Cầu ăn.","detail":"Một cây linh dược mọc từ trong khe núi trên Thái Cổ Thần Sơn, được Nhóc Tỳ ngắt và đưa cho con vật nhỏ màu vàng Mao Cầu ăn ngon lành khi vừa lên tới thần sơn.","nguon":["@c0233"]},{"id":"thong-dao-nam-mau","name":"Thông đạo năm màu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tổ phụ thiếu nữ áo tím"],"trangThai":"dang-co","blurb":"Con đường năm màu nối liền trời cao trên đỉnh Thần Sơn, đưa đại quân tới Bắc Hải.","detail":"Con đường năm màu nối liền trời cao ở đỉnh Thần Sơn, đưa đại quân sáu bảy trăm người tới Bắc Hải cách xa mấy trăm vạn dặm. Cần tôn giả (tổ phụ thiếu nữ áo tím) mới mở ra được.","nguon":["@c0234"]},{"id":"bao-thuyen-hat-cay","name":"Bảo thuyền hạt cây","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thần bộc Hoàng Kim Thú"],"trangThai":"hong","blurb":"Thuyền nhỏ điêu khắc từ một hạt cây, thả xuống biển biến lớn như núi di động.","detail":"Thuyền nhỏ điêu khắc từ một hạt cây, thả xuống biển liền biến lớn như một tòa núi di động, tốc độ như phi hành. Lão bộc dùng nó vượt biển nhưng sau ngàn dặm thì bị quái ngư bạc phóng lôi đình đánh nổ tung.","nguon":["@c0234"]},{"id":"tam-da-thu-che-cho","name":"Tấm da thú","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thần bộc Hoàng Kim Thú"],"trangThai":"hong","blurb":"Hai tấm da thú phủ kín trời biển, phù văn dày đặc thánh huy, dùng che chở và nâng đỡ người bay.","detail":"Hai tấm da thú lão bộc ném ra phủ kín cả trời biển, khắc phù văn dày đặc phát thánh huy; dùng để che chở đoàn người và làm nền như lục địa nâng đỡ hơn ba trăm người bay trên không. Về sau bị Thánh Giả không đầu dùng chiến mâu vàng chém thành nhiều mảnh.","nguon":["@c0234"]},{"id":"co-bao-than-son-sung-thu","name":"Cổ bảo Thần Sơn (sừng thú)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Thần bộc Hoàng Kim Thú"],"trangThai":"dang-co","blurb":"Chiếc sừng thú cổ bảo của Thần Sơn, thổi ra thanh âm phá tan phù văn Hải Ma.","detail":"Chiếc sừng thú là cổ bảo của Thần Sơn; khi thổi phát ra thanh âm như tiếng gầm thét của Thần Linh, xuyên thủng phong ba và phá tan phù văn của đại trận Hải Ma, mở đường cho đoàn chạy trốn. Dùng để ứng phó những nguy cơ nghiêm trọng như thế.","nguon":["@c0234"]},{"id":"chien-mau-vang","name":"Chiến mâu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thánh Giả không đầu"],"trangThai":"dang-co","blurb":"Thanh chiến mâu vàng óng của Thánh Giả không đầu, chém rời cả bầu trời.","detail":"Thanh chiến mâu vàng óng trong tay Thánh Giả không đầu; chém rời cả bầu trời, cắt tấm da thú che chở của đoàn thành nhiều mảnh.","nguon":["@c0234"]},{"id":"long-giao-tien","name":"Long Giao Tiễn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Vật phẩm màu vàng Thạch Hạo điều động để thoát ly chiến trường nhanh chóng.","detail":"Long Giao Tiễn là pháp bảo màu vàng của Thạch Hạo. Trong cuộc thảm sát của Thánh Giả không đầu, Thạch Hạo im lặng điều động Long Giao Tiễn màu vàng để nhanh chóng thoát ly khỏi chiến trường về phía trước.","nguon":["@c0235"]},{"id":"sung-thu-chi-bao","name":"Sừng thú","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo","soHuu":[],"trangThai":"dang-co","blurb":"Sừng cổ thú chí bảo, thần bộc thổi phát gợn sóng bạc chấn động biển; dùng như thuyền lớn lướt sóng và bọc bảo quang bảo vệ.","detail":"Sừng thú là chí bảo của các thần bộc Thần Sơn Thái Cổ. Thổi lên phát ra gợn sóng bạc chấn động biển đông, có thể dùng như thuyền lớn lướt sóng và bọc bảo quang che chở người mang. Ai cầm sừng thú mới tránh được kiếp nạn từ chiến mâu vàng của Thánh Giả không đầu, song khi vào sâu vùng biển cấm thì tiêu hao thần lực rất lớn.","nguon":["@c0235"]},{"id":"chien-mau-vang-thanh-gia","name":"Chiến mâu vàng óng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thánh Giả không đầu"],"trangThai":"dang-co","blurb":"Vũ khí của Thánh Giả không đầu Thượng Cổ, quẹt qua là sinh linh nổ tung, có thể cắt cả bầu trời.","detail":"Chiến mâu vàng óng là vũ khí của Thánh Giả không đầu chết trận từ Thượng Cổ. Uy lực khủng khiếp: chỉ cần quẹt qua là sinh linh nổ tung, thần bộc mạnh cũng bị diệt, đường mâu như cắt cả bầu trời; đánh tan cả gợn sóng bạc do sừng thú tạo ra.","nguon":["@c0235"]},{"id":"u-linh-thuyen","name":"U Linh Thuyền","aliases":["thuyền giấy màu đen","thuyền giấy máu đen"],"cn":"","category":"khac","categoryLabel":"Di tích","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Những chiếc thuyền lạc đường từ thời Thượng Cổ trong vùng biển tử vong, có đuốc xanh, không âm thanh; tới gần sẽ bị giết.","detail":"U Linh Thuyền là những chiếc chiến thuyền lạc đường từ thời Thượng Cổ trôi dạt trong vùng biển tử vong. Chúng thắp đuốc xanh, không phát ra âm thanh, kẻ tới gần sẽ bị giết. Cuối chương, Thạch Hạo bị sóng hất chìm rồi đạp nước xông thẳng lên một chiếc U Linh Thuyền như vậy.","nguon":["@c0235"]},{"id":"khoi-xuong-thu-thach-van","name":"Khối xương thú","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Vân"],"trangThai":"da-dung","blurb":"Khối xương thú cháy hừng hực khắc phù văn, hóa thành mặt trời nhỏ, dùng làm vật công kích.","detail":"Thạch Vân ném khối xương thú này nổ tung trên U Linh Thuyền với danh nghĩa kích thích thuyền bạo động hại bạch tuộc, thực chất nhằm hại Thạch Hạo đang mắc kẹt bên trong.","nguon":["@c0236"]},{"id":"tam-xoa-kich-mau-vang","name":"Tam Xoa Kích màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Hậu nhân Hải Thần"],"trangThai":"dang-co","blurb":"Binh khí màu vàng của hậu nhân Hải Thần tại lối vào hang ổ thật của Côn Bằng.","detail":"Hậu nhân Hải Thần dùng Tam Xoa Kích màu vàng chấn động một cái, kim quang bùng lên như sóng lớn, khiến kẻ cãi lời cùng đám người xung quanh nổ tung thành sương máu.","nguon":["@c0239"]},{"id":"viem-trap-than-tinh","name":"Viêm Trấp thần tính","cn":"","category":"nguyen-lieu","categoryLabel":"Vật chất thần tính","phamCap":"có thể luyện Thánh Khí","soHuu":[],"trangThai":"khong-ro","blurb":"Tia vật chất thần tính tồn tại trong cơ thể Hỏa Viêm Ngư, cực kỳ hiếm và có giá trị luyện khí.","detail":"Trong cơ thể mỗi con Hỏa Viêm Ngư có một tia Viêm Trấp thần tính nhưng hàm lượng rất thấp, phải mấy ngàn con mới luyện ra một giọt. Vật chất này có thể dùng để luyện Thánh Khí.","nguon":["@c0239"]},{"id":"hoa-phu","name":"Hỏa Phù","cn":"","category":"khac","categoryLabel":"Phù văn hỏa đạo","phamCap":"không rõ","soHuu":["Hỏa Viêm Ngư"],"trangThai":"khong-ro","blurb":"Loại phù do Hỏa Viêm Ngư trời sinh thai nghén, gắn với năng lực Hỏa Tinh của chủng tộc này.","detail":"Hỏa Viêm Ngư trong truyền thuyết tinh thông Hỏa Tinh và có thể thai nghén Hỏa Phù. Khi đàn cá số lượng lớn cùng xuất hiện, uy thế của Hỏa Phù hợp lại trở nên đáng sợ.","nguon":["@c0239"]},{"id":"con-moc","name":"Côn Mộc","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Thần mộc","phamCap":"thần mộc truyền thuyết","soHuu":[],"trangThai":"xuất hiện trong cánh cửa cấm kỵ","blurb":"Côn Mộc là thần mộc truyền thuyết được xem như cây thông thiên nối liền người và thần. Tại cánh cửa cấm kỵ xuất hiện một khúc gỗ mục có long văn, thánh huy cùng một chiếc lá óng ánh không mục nát, khiến quần hùng điên cuồng tranh đoạt.","detail":"Côn Mộc được nhận ra qua khúc gỗ mục to bằng thùng nước, toàn thân có long văn, tỏa thánh huy và hào quang thần tính nồng nặc. Bên cạnh còn có chiếc lá trong suốt không mục nát ngâm trong dòng nước, được cho là trợ giúp ngộ đạo và tăng tốc tu hành; sự xuất hiện của nó khiến vô số sinh linh lao vào dòng sông cấm kỵ rồi nổ tung thành tro bụi.","nguon":["@c0240"]},{"id":"chien-kich-mau-vang","name":"Chiến kích màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo còn sót lại từ Thượng Cổ","soHuu":["Hậu nhân Hải Thần"],"trangThai":"Đang được hậu nhân Hải Thần sử dụng","blurb":"Binh khí màu vàng của hậu nhân Hải Thần, có thể chém sóng biển hoàng kim và đối kháng kiếm gãy của Thạch Hạo.","detail":"Chiến kích màu vàng là binh khí của thiếu niên Hải Tộc được xưng là hậu nhân Hải Thần. Nó chém qua sóng biển hoàng kim, đỡ trực diện kiếm gãy của Thạch Hạo trong lúc thần hoàn Mười Động Thiên bao phủ chiến trường, làm ánh sáng bùng nổ và chấn động quần hùng. Chương này mô tả nó là chí bảo còn sót lại từ Thượng Cổ, khí thế siêu phàm thoát tục.","nguon":["@c0241"]},{"id":"chien-mau-mau-mau","name":"Chiến mâu màu máu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thần mâu","soHuu":["Thiếu niên Hỏa Viêm Ngư hóa hình"],"trangThai":"Đang được thiếu niên Hỏa Viêm Ngư hóa hình sử dụng","blurb":"Binh khí màu máu của thiếu niên Hỏa Viêm Ngư hóa hình, được dùng để đánh thẳng vào hậu nhân Hải Thần.","detail":"Chiến mâu màu máu là binh khí trong tay thiếu niên Hỏa Viêm Ngư hóa hình. Nó có sắc đỏ như được đánh bóng từ máu tươi, theo chủ nhân lăng không lao tới tập kích hậu nhân Hải Thần. Trong giao chiến, chiến mâu này va chạm với chiến kích màu vàng, phát ra âm thanh điếc tai và làm phù văn bùng lên đầy trời.","nguon":["@c0241"]},{"id":"tan-cot-con-bang","name":"Tàn cốt Côn Bằng","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Di cốt của một trong Thập Hung Thái Cổ","soHuu":[],"trangThai":"Được dùng để mở phong ấn lối vào hang ổ Côn Bằng","blurb":"Mảnh xương rạn nứt của Côn Bằng Thái Cổ, được các cường giả dùng để phá mở lối vào hang ổ Côn Bằng.","detail":"Tàn cốt Côn Bằng là một mảnh xương rạn nứt được nhận ra là di cốt của Côn Bằng, một trong Thập Hung Thái Cổ. Khi được điều khiển, nó phát ra kim quang như sóng biển và tràn ra phù văn màu đen. Đám cường giả sinh linh lục địa dùng mảnh tàn cốt này để làm phong ấn lối vào hang ổ Côn Bằng nứt ra, khiến sương mù hỗn độn tràn ra và mở màn cuộc tranh đoạt bảo thuật bên trong.","nguon":["@c0241"]},{"id":"tu-tinh-kiem","name":"Tử Tinh Kiếm","cn":"","aliases":["phi kiếm tím"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tử Tinh Ngư"],"trangThai":"đang sử dụng","blurb":"Tử Tinh Kiếm là phi kiếm màu tím của Tử Tinh Ngư, dài không quá nửa xích nhưng cực kỳ sắc bén. Khi được khí tím thúc động, nó hóa thành vầng mặt trời tím quét ngang cường giả trong đạo tràng Thái Cổ.","detail":"Thanh phi kiếm này được mô tả là luyện từ tử tinh, không tạp chất, mang khí Canh Kim và độ xuyên phá rất cao. Trong đạo tràng Côn Bằng, Tử Tinh Ngư dùng nó giết sạch cường giả cản đường, khiến quần hùng thèm thuồng vì phẩm chất sắc bén của nó.","nguon":["@c0242"]},{"id":"kim-tien","name":"Kim tiên","cn":"","aliases":["roi vàng"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thanh Vân"],"trangThai":"đang sử dụng","blurb":"Kim tiên là vũ khí màu vàng của Thanh Vân khi truy sát Hùng Hài Tử. Nó có hình dạng đặc biệt, giống kiếm không mũi nhọn hơn là roi mềm thông thường.","detail":"Kim tiên có bốn góc cạnh, gồm hai mươi tám đốt, hình như đoản côn có cán, không phải nhuyễn tiên. Thanh Vân dùng nó trong lần tái đối đầu Thạch Hạo tại đạo tràng Thái Cổ.","nguon":["@c0242"]},{"id":"di-vat-con-bang","name":"Di vật Côn Bằng","cn":"","aliases":["Di cốt Côn Bằng","Máu cốt vảy lông Côn Bằng"],"category":"nguyen-lieu","categoryLabel":"Di vật","phamCap":"Di vật Thái Cổ","soHuu":["Hải Tộc","Bộ tộc Hải Ma","Sinh linh lục địa"],"trangThai":"da-dung","blurb":"Di vật Côn Bằng gồm máu, cốt, vảy và lông, là chìa khóa khiến cửa đá tổ Côn Bằng chấp thuận mở ra.","detail":"Các thế lực phải gộp những phần di vật Côn Bằng rời rạc: Bằng Cốt trong tay Hải Tộc, vảy cá nát do bộ tộc Hải Ma góp, nửa tàn vũ lông tơ và vết máu đen của sinh linh lục địa. Khi máu, cốt, vảy, lông hợp lại, cửa đá tổ Côn Bằng mới mở, cho quần hùng tiến vào đạo tràng bên trong.","nguon":["@c0243"]},{"id":"bia-da-con-bang","name":"Bia đá Côn Bằng","cn":"","category":"khac","categoryLabel":"Di vật khắc chữ cổ","phamCap":"Di vật Côn Bằng","soHuu":["Mao Cầu"],"trangThai":"dang-co","blurb":"Các tấm bia đá cổ do Mao Cầu kéo về trong hang ổ Côn Bằng. Chúng không ghi bí pháp thần thông mà ghi tiểu sử cuộc đời Côn Bằng khổ tu.","detail":"Mao Cầu đã trộm về tổng cộng tám tấm bia đá Côn Bằng có chữ viết xa xưa. Nội dung các bia đá không phải bảo thuật Côn Bằng mà là ghi chép về cuộc đời khổ tu của Côn Bằng; một tấm còn nhắc vùng biển này giống nơi sinh của Côn Bằng, thích hợp cho thiếu niên mài giũa.","nguon":["@c0244"]},{"id":"linh-duoc-hang-o-con-bang","name":"Linh dược hang ổ Côn Bằng","cn":"","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Không rõ","soHuu":["Mao Cầu","Thạch Hạo"],"trangThai":"da-dung","blurb":"Linh dược mọc um tùm trong vài vùng đất cấm của hang ổ Côn Bằng. Mao Cầu và Thạch Hạo đều ăn chúng trong thời gian lưu lại nơi đây.","detail":"Trong hang ổ Côn Bằng có vài vùng đất cấm mọc đầy linh dược. Mao Cầu hái ăn rất nhiều đến mức bụng căng tròn, miệng mũi tai đều trào linh khí; Thạch Hạo cũng ăn linh dược như nhai củ cải, cho thấy dược lực nơi đây rất mạnh, người bình thường khó chịu nổi.","nguon":["@c0244"]},{"id":"kien-gay","name":"Kiến gãy","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Kiến gãy là pháp bảo dạng kiếm phát ra luồng ánh kiếm trong lúc các thần bộc vây công Thạch Hạo. Một nhát kiếm khiến một thần phó phải lui lại.","detail":"Trong cuộc vây công của tứ đại thần bộc, Kiến gãy phát uy bằng một luồng ánh kiếm bổ ra, buộc một thần phó phải lùi. Pháp bảo này phối hợp với Đả Thần Thạch và thần hoàn Động Thiên giúp Thạch Hạo phá thế đánh úp.","nguon":["@c0246"]},{"id":"tui-can-khon-thieu-nu-ao-den","name":"Túi Càn Khôn của thiếu nữ áo đen","cn":"","aliases":["Túi Càn Khôn"],"category":"phap-bao","categoryLabel":"Pháp bảo chứa đồ","phamCap":"Chưa rõ","soHuu":["Thiếu nữ áo đen"],"trangThai":"dang-co","blurb":"Chiếc Túi Càn Khôn tinh xảo của thiếu nữ áo đen, luyện từ da hung thú và buộc bằng dây vàng.","detail":"Túi nhỏ này chứa nhiều đồ ăn ngon, rượu thơm và linh dược cực phẩm. Thạch Hạo đánh giá nó có vẻ tốt hơn Túi Càn Khôn của mình, đồng thời cũng nảy ý cướp lấy, trong khi thiếu nữ áo đen cũng có tâm tư tương tự với túi của hắn.","nguon":["@c0247"]},{"id":"thit-thanh-loan","name":"Thịt Thanh Loan","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Bảo dược huyết nhục","phamCap":"Sinh linh thuần huyết","soHuu":["Thạch Hạo","Thiếu nữ áo đen"],"trangThai":"da-dung","blurb":"Thịt Thanh Loan dài mười mấy mét, được xưng là sinh linh thuần huyết và ẩn chứa nhiều thần năng.","detail":"Trong bữa tiệc trên U Linh Thuyền, Thạch Hạo và thiếu nữ áo đen ăn hơn nửa con Thanh Loan, dùng huyết nhục bảo dược này cùng Hầu Nhi Tửu để bổ sung và củng cố thân thể. Thiếu nữ áo đen ăn còn nhanh hơn Thạch Hạo, khiến hắn chịu thua ở mặt ăn uống.","nguon":["@c0247"]},{"id":"dai-kich-mau-vang","name":"Đại kích màu vàng","cn":"","category":"phap-bao","categoryLabel":"Binh khí","phamCap":"không rõ","soHuu":["Mạc Thương"],"trangThai":"đang sử dụng","blurb":"Đại kích màu vàng là binh khí của Mạc Thương trong trận quyết chiến trên tế đàn.","detail":"Khi Mạc Thương ra tay, đại kích màu vàng tăng vọt hơn mười trượng, phù văn bao phủ và bổ xuống Thạch Hạo. Nó là vũ khí chính giúp Mạc Thương mở đầu cuộc chiến sinh tử với Thạch Hạo trên tế đàn.","nguon":["@c0252"]},{"id":"than-chieu-dang","name":"Thần Chiếu Đăng","cn":"","aliases":["Thần Chiếu Thanh Đồng Đăng","Thanh Đông Đăng"],"category":"phap-bao","categoryLabel":"Thái cổ pháp khí","phamCap":"Thái cổ pháp khí","soHuu":["Hàn Thiên"],"trangThai":"bị Hàn Thiên đoạt trong động phủ Côn Bằng","blurb":"Cổ đăng thần bí dùng thần huyết làm dầu, vốn được đặt trong động phủ Côn Bằng để chiếu sáng.","detail":"Thần Chiếu Thanh Đồng Đăng là thái cổ pháp khí cường đại tuyệt luân, được hai Tôn Giả tranh đoạt. Hàn Thiên mặc giáp đỏ thẫm lao vào và đoạt cổ đăng khỏi tay họ; trong động phủ Côn Bằng, vật này chỉ được dùng như đèn chiếu sáng, càng làm nổi bật quy mô thần tàng bên trong.","nguon":["@c0254"]},{"id":"duoc-tan-dan-phuong-hai-than","name":"Dược tán đan phương Hải Thần","cn":"","aliases":["Dược tán","viên đan xanh lam"],"category":"dan-duoc","categoryLabel":"Bảo dược","phamCap":"Luyện từ thiên địa thần trân và một phần thánh dược","soHuu":["Mạc Thương"],"trangThai":"đã dùng","blurb":"Bảo dược Mạc Thương dùng để chữa vết thương xuyên ngực do Thạch Hạo gây ra.","detail":"Viên đan phát ánh xanh lam, tỏa hương khí khắp hải vực. Nó không phải Hải Thần Đan chân chính mà là dược tán luyện theo đan phương Hải Thần lưu lại, trộn thiên địa thần trân và một phần thánh dược, có thể khiến da thịt mọc lại từ xương trắng và đưa chiến lực Mạc Thương về đỉnh phong.","nguon":["@c0254"]},{"id":"linh-hai-than-dich-con-bang","name":"Linh hải / thần dịch Côn Bằng","cn":"","aliases":["Ao thần dịch","Thần dịch Côn Bằng"],"category":"dan-duoc","categoryLabel":"Thần dịch","phamCap":"Giá trị liên thành","soHuu":["Thạch Hạo"],"trangThai":"Thạch Hạo thu hơn mười giọt cuối","blurb":"Ao thần dịch màu xanh lam như ngọc tủy nằm trong đạo tràng Côn Bằng.","detail":"Linh hải là tinh hoa biển cả ngưng tụ, màu xanh lam như ngọc tủy. Tuy không bằng Bất Lão tuyền, nó vẫn cực kỳ quý hiếm, có thể dùng làm thuốc và luyện khí; khi mọi người tranh đoạt, Thạch Hạo kịp thu hơn mười giọt cuối.","nguon":["@c0254"]},{"id":"te-dan-lo-cot-chien-tranh","name":"Tế đàn / lô cốt chiến tranh","cn":"","aliases":["Tế đàn","Lô cốt chiến tranh"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Mạc Thương"],"trangThai":"Mạc Thương mang theo","blurb":"Pháp khí dạng tế đàn được Mạc Thương sử dụng trong đạo tràng Côn Bằng.","detail":"Mạc Thương nhảy lên tế đàn, phát tia sáng đánh chết một mảng cường giả để mở đường. Sau đó tế đàn thu nhỏ, xoay tròn rơi xuống bên hắn và hóa thành lô cốt chiến tranh có thể sát phạt tùy thời.","nguon":["@c0254"]},{"id":"than-tuu-binh-ngoc-con-bang","name":"Thần tửu bình ngọc Côn Bằng","cn":"","aliases":["bình ngọc Côn Bằng","thần tửu"],"category":"dan-duoc","categoryLabel":"Thần dịch","phamCap":"thần dịch trân quý","soHuu":["Thạch Hạo"],"trangThai":"Thạch Hạo đoạt được","blurb":"Thần tửu trong bình ngọc của Côn Bằng là thần dịch chân chính, được xem là có tác dụng trị liệu khởi tử hồi sinh. Thạch Hạo đoạt được bình này trong cuộc hỗn chiến ở động phủ Côn Bằng.","detail":"Bình ngọc và chén ngọc được phát hiện sau khi một cửa đá trong đạo tràng Côn Bằng mở ra. Thần tửu bên trong được miêu tả trân quý hơn Hầu Nhi Tửu, do thần thánh cổ dược luyện thành; sau khi Mao Cầu ôm bình bỏ chạy và làm phá phong, Thạch Hạo kịp thu bình vào Túi Càn Khôn.","nguon":["@c0255"]},{"id":"ngoc-tinh-binh","name":"Ngọc Tịnh Bình","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Chí bảo","phamCap":"chí bảo","soHuu":[],"trangThai":"đang bị tranh đoạt","blurb":"Ngọc Tịnh Bình là bảo bình cắm hoa tươi trong thạch thất sâu của động phủ Côn Bằng. Mọi người ban đầu tưởng hoa là thánh dược, nhưng sau nhận ra bảo bình mới là báu vật.","detail":"Bảo bình có khí tức sinh mệnh tràn đầy, thông thể ôn nhuận và được nhận xét giống hệt chí bảo của Tiểu Tây Thiên. Việc Côn Bằng chỉ dùng nó để cắm hoa càng cho thấy lai lịch bất phàm, khiến bốn năm vương hầu lập tức đại chiến tranh đoạt.","nguon":["@c0255"]},{"id":"bo-doan-con-bang","name":"Bồ đoàn Côn Bằng","cn":"","aliases":["bồ đoàn"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Thạch Hạo"],"trangThai":"Thạch Hạo đoạt được","blurb":"Bồ đoàn Côn Bằng là vật Côn Bằng từng ngồi nghỉ trong động phủ, có bản thể bện từ rễ cây non màu xanh biếc như ngọc. Nó nặng hơn mười vạn cân và cực kỳ kiên cố.","detail":"Trong khi nhiều người tranh Ngọc Tịnh Bình, Thạch Hạo nhắm đến bồ đoàn này. Khi lộ bản thể, bồ đoàn tỏa khí tức tường hòa, nặng hơn mười vạn cân; Thạch Hạo dùng nó như búa đánh văng đại ấn của lão giả Hóa Linh cảnh, cho thấy độ cứng chắc vượt thường.","nguon":["@c0255"]},{"id":"chan-giao-dan-doc-dan","name":"Chân Giao Đan","cn":"","aliases":["độc đan","độc tán Chân Giao"],"category":"dan-duoc","categoryLabel":"Độc đan","phamCap":"đan dược thất bại","soHuu":[],"trangThai":"hóa thành sương mù độc","blurb":"Chân Giao Đan là lò đan Côn Bằng từng luyện từ Chân Giao Thái Cổ nhưng thất bại. Vì không được xử lý, nó hóa thành độc đan, độc tán và thả ra sương mù đen kịch độc.","detail":"Sương mù đen từ dược lô giết hại nhiều người, kể cả vương hầu, trước khi bị Hàn Thiên dùng Thần Chiếu Đăng luyện hóa sạch. Giao Tôn Giả thuộc Giao tộc cảm ứng được dấu vết Chân Giao trong độc tán này.","nguon":["@c0255"]},{"id":"cot-thap","name":"Cốt Tháp","cn":"","aliases":["tiểu tháp sáng long lanh"],"category":"phap-bao","categoryLabel":"Bảo khí","phamCap":"không rõ","soHuu":["Thạch Hạo"],"trangThai":"ẩn trên tóc Thạch Hạo","blurb":"Cốt Tháp là tiểu tháp sáng long lanh cao chưa đầy một tấc, ẩn trên tóc Thạch Hạo. Nó lần đầu lên tiếng trong động phủ Côn Bằng và giao dịch bằng Hỗn Độn Thổ.","detail":"Cốt Tháp phát ra ý chí yếu ớt, đòi trao đổi với Thạch Hạo: nuốt hơn phân nửa Hỗn Độn Thổ của Linh Lung Tháp để đổi lấy một lần cơ hội cứu mạng, có thể dùng để trấn giết địch hoặc phá hư không bỏ chạy khi gặp tuyệt cảnh. Nó còn được nhắc là bảo khí từng khiến Liễu Thần nghiêm túc và không muốn đề cập.","nguon":["@c0256"]},{"id":"linh-lung-thap","name":"Linh Lung Tháp","cn":"","aliases":["bảo tháp Hỗn Độn Thổ"],"category":"phap-bao","categoryLabel":"Khí phôi","phamCap":"thánh vật","soHuu":["Thạch Hạo","Cốt Tháp"],"trangThai":"bị Cốt Tháp nuốt phần lớn Hỗn Độn Thổ","blurb":"Linh Lung Tháp là bảo tháp đúc từ Hỗn Độn Thổ trong hàn đàm Luyện Binh Địa. Nó có linh tính, trân quý hơn kiếm phôi Long Cốt Thiết.","detail":"Bảo tháp này là khí phôi thời Thái Cổ, lưu lại hỗn độn phù văn và được xem là bảo cụ khó phá hủy. Thạch Hạo bắt được nó giữa vòng vây tranh đoạt, nhưng Cốt Tháp sau đó nuốt hơn phân nửa Hỗn Độn Thổ, chỉ để lại mảnh vụn cho Đả Thần Thạch.","nguon":["@c0256"]},{"id":"bo-doan-con-moc","name":"Bồ đoàn côn mộc","cn":"","aliases":["bồ đoàn màu xanh"],"category":"phap-bao","categoryLabel":"Thần trân","phamCap":"không rõ","soHuu":["Thạch Hạo"],"trangThai":"được thu vào Túi Càn Khôn","blurb":"Bồ đoàn côn mộc là bồ đoàn màu xanh bện từ côn mộc, từng được Côn Bằng ngồi qua. Nó có thể liên thông Thần giới và tiếp cận đạo bổn nguyên.","detail":"Trong động phủ Côn Bằng, vật này khiến nhiều cường giả và cả Tôn Giả tranh đoạt. Thạch Hạo dùng mười tòa Động Thiên hóa thần hoàn chém địch rồi thu bồ đoàn vào Túi Càn Khôn.","nguon":["@c0256"]},{"id":"kiem-thai-long-cot-thiet","name":"Kiếm thai Long Cốt Thiết","cn":"","category":"phap-bao","categoryLabel":"Khí phôi","phamCap":"thánh bảo","soHuu":[],"trangThai":"ở hàn đàm Luyện Binh Địa","blurb":"Kiếm thai Long Cốt Thiết là kiếm phôi thông linh trong hàn đàm Luyện Binh Địa. Nó được đúc từ Long Cốt Thiết, tài liệu cực phẩm gắn với Chân Long vẫn lạc trên quặng sắt.","detail":"Khí phôi này thuộc nhóm bảo cụ Côn Bằng từng luyện chế nhưng chưa tế luyện hoàn tất. Dù rất quý, nó vẫn được đánh giá kém trân quý hơn bảo tháp Hỗn Độn Thổ trong cùng hàn đàm.","nguon":["@c0256"]},{"id":"thien-hoang","name":"Thiên Hoang","cn":"","category":"than-khi","categoryLabel":"Thần binh","phamCap":"Chí cao Thiên Giai","soHuu":["Côn Bằng"],"trangThai":"gãy ba đoạn","blurb":"Thiên Hoang là đại kích cổ phác trong truyền thuyết, một trong mười đại binh khí thời thái cổ. Khi xuất hiện trên tế đàn Côn Bằng, nó đã bị cắt thành ba đoạn nhưng vẫn còn thần uy đáng sợ.","detail":"Thiên Hoang từng theo Côn Bằng chinh chiến cả đời, được xưng là chí cao trong Thiên Giai và một trong mười đại binh khí thời thái cổ. Có lời đồn nó được luyện từ Chân Long hoặc từ phù cốt Côn Bằng. Tại tế đàn, đại kích nằm giữa các thần binh, lưỡi kích ảm đạm, thân binh khí bao quanh khí hỗn độn; dù đã gãy ba đoạn, nó vẫn phóng ra tinh hà đánh bay người tới gần, khiến cả Tôn Giả và các thiên tài đều không thể câu thông hay thu lấy.","nguon":["@c0257"]},{"id":"chuy-thu-tinh-xao","name":"Chủy thủ tinh xảo","cn":"","category":"than-khi","categoryLabel":"Thần binh thái cổ","phamCap":"không rõ","soHuu":["Côn Bằng"],"trangThai":"trên tế đàn Côn Bằng","blurb":"Chủy thủ tinh xảo là một trong các binh khí thái cổ đặt trên tế đàn Côn Bằng. Nó thuộc nhóm pháp khí Côn Bằng từng dùng nhưng không đáp lại thần thức của người tranh đoạt.","detail":"Chủy thủ tinh xảo nằm trong số tám chín kiện binh khí ở nơi cao nhất của tế đàn, cùng với quạt vàng, thước đen và Thiên Hoang. Khi mọi người thử dùng thần thức câu thông, nó không có phản ứng, cho thấy các thần binh trên tế đàn không dễ bị thu phục.","nguon":["@c0257"]},{"id":"quat-mau-vang","name":"Quạt màu vàng","cn":"","category":"than-khi","categoryLabel":"Thần binh thái cổ","phamCap":"không rõ","soHuu":["Côn Bằng"],"trangThai":"trên tế đàn Côn Bằng","blurb":"Quạt màu vàng là một kiện thần binh thái cổ xuất hiện trên tế đàn Côn Bằng. Nó nằm trong nhóm pháp khí Côn Bằng từng sử dụng.","detail":"Quạt màu vàng được đặt gần Thiên Hoang ở nơi cao nhất của tế đàn. Dù mọi người, kể cả cường giả cấp Tôn Giả, cố dùng thần thức câu thông, kiện binh khí này vẫn không đáp lại.","nguon":["@c0257"]},{"id":"thuoc-mau-den","name":"Thước màu đen","cn":"","category":"than-khi","categoryLabel":"Thần binh thái cổ","phamCap":"không rõ","soHuu":["Côn Bằng"],"trangThai":"trên tế đàn Côn Bằng","blurb":"Thước màu đen là binh khí thái cổ nằm trên tế đàn Côn Bằng. Nó cùng các thần binh khác không để người ngoài dễ dàng thu phục.","detail":"Thước màu đen xuất hiện trong nhóm tám chín kiện binh khí trên tế đàn, được xem là pháp khí Côn Bằng từng dùng. Khi mọi người phát thần thức để câu thông, nó vẫn không có phản ứng.","nguon":["@c0257"]},{"id":"kiem-thai-phoi-tho-hon-don-tho","name":"Kiếm thai / phôi thô Hỗn Độn Thổ","cn":"","aliases":["Kiếm thai","Phôi thô"],"category":"phap-bao","categoryLabel":"Kiếm phôi linh tính","phamCap":"không rõ","soHuu":[],"trangThai":"đang ở tế đàn Côn Bằng","blurb":"Các kiếm thai và phôi thô có linh tính từng ẩn trong hàn đàm, sau đó chạy tới thần sào Côn Bằng. Chúng bị chấn động sau khi Thạch Hạo lấy đi tòa tháp Hỗn Độn Thổ.","detail":"Nhóm kiếm thai và phôi thô từng xuất hiện trong hàn đàm của Luyện Binh Địa. Sau biến cố Thạch Hạo bắt đi tòa tháp xây từ Hỗn Độn Thổ, chúng chạy tới thần sào và xen lẫn với những binh khí thần vật thái cổ trên tế đàn. Khi mọi người phát thần thức câu thông, chúng cũng không đáp lại.","nguon":["@c0257"]},{"id":"khoi-cot-mau-vang-phu-cot-con-bang","name":"Khối cốt màu vàng","cn":"","aliases":["Phù cốt Côn Bằng","Khối cốt màu vàng xen vân đen"],"category":"nguyen-lieu","categoryLabel":"Di cốt bảo vật","phamCap":"không rõ","soHuu":["Côn Bằng"],"trangThai":"trên bệ đá tế đàn","blurb":"Khối cốt màu vàng xen vân đen nằm trên bệ đá như quan tài ở cuối tế đàn. Phù văn trên đó chằng chịt, lưu chuyển áo nghĩa chư thiên, khiến mọi người lập tức nhận ra đây là vật then chốt.","detail":"Khối cốt được đặt trên một bệ đá nằm ngang như quan tài phía trước tế đàn. Nó có màu vàng, bên trong xen lẫn đường vân màu đen, phù văn dày đặc lưu chuyển áo nghĩa chư thiên. Sự xuất hiện của nó khiến ánh mắt mọi người đều dồn tới và có người kêu lên rằng chính là vật họ tìm kiếm.","nguon":["@c0257"]},{"id":"nguyen-thuy-phu-cot-con-bang","name":"Nguyên thủy phù cốt Côn Bằng","cn":"","aliases":["Phù Cốt Côn Bằng","bảo cốt Côn Bằng"],"category":"phap-bao","categoryLabel":"Phù cốt thái cổ","phamCap":"Một trong mười đại bảo thuật thời thái cổ","soHuu":[],"trangThai":"đang bị tranh đoạt","blurb":"Nguyên thủy phù cốt Côn Bằng là bảo vật chứa thần thông chí cao và áo nghĩa vô thượng của Côn Bằng. Nó lộ diện tại bệ đá trong thái cổ thần tàng, dẫn phát pháp tướng Côn Bằng và khiến quần hùng bùng nổ đại hỗn chiến.","detail":"Khối phù cốt có phù văn lưu động, hào quang như ngân hà, từng hiện pháp tướng Côn Bằng che kín thiên địa, uy áp mạnh tới mức nhiều người ngã xuống và cả Tôn Giả cũng lung lay. Dù bị phát hiện có vết nứt, mọi người nhận định phù văn bên trong không thiếu thốn, vẫn có thể tham ngộ; khi bị tiếp cận, bảo cốt kháng cự đẩy người chộp ra nhưng không phản kích kịch liệt.","nguon":["@c0258"]},{"id":"phap-truong-kham-than-thach","name":"Pháp trượng khảm thần thạch","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp trượng","phamCap":"không rõ","soHuu":["Thiếu nữ thiên tài Nhân Ngư Tộc"],"trangThai":"đang sử dụng","blurb":"Pháp trượng khảm thần thạch là vũ khí của thiếu nữ thiên tài Nhân Ngư Tộc trong cuộc tranh phù cốt Côn Bằng. Nó được dùng để tung phù văn và lôi điện chống lại Mạc Thương.","detail":"Pháp trượng dài hơn thước, khảm một viên thần thạch sáng chói. Khi thiếu nữ Nhân Ngư Tộc ra tay, pháp trượng phóng phù văn như sóng cùng hàng vạn luồng lôi điện, nhưng vẫn không giúp nàng thắng được Mạc Thương.","nguon":["@c0258"]},{"id":"ao-mau-con-bang","name":"Ao máu Côn Bằng","cn":"","category":"khac","categoryLabel":"Vật truyền thừa","phamCap":"Truyền thừa Thái Cổ","soHuu":[],"trangThai":"dang-co","blurb":"Ao máu đỏ rực lấp lánh trong nhà đá cuối Hóa Ma động, bắn ra phù văn Côn Bằng và tái hiện toàn bộ bảo thuật truyền thừa.","detail":"Nằm sau hai cánh cửa đá ở cuối Hóa Ma động, trong một không gian sáng sủa thần thánh, ao máu Côn Bằng đỏ tươi và lấp lánh không ngừng bắn ra phù văn Côn Bằng. Toàn bộ bảo thuật Côn Bằng được tinh luyện, ẩn giấu và tái hiện từ ao máu này: các ký hiệu vàng đen tổ hợp thành chim Côn Bằng rồi hóa cá đen, phô bày truyền thừa hoàn chỉnh và tạo áp lực khủng khiếp lên người đứng trước nó.","nguon":["@c0261"]},{"id":"bao-cot-con-bang","name":"Bảo cốt Côn Bằng","cn":"","category":"khac","categoryLabel":"Bảo vật truyền thừa","phamCap":"Truyền thừa Côn Bằng","soHuu":[],"trangThai":"Sáu miếng bị các thế lực chia cắt sau đại chiến trên tế đàn","blurb":"Sáu miếng bảo cốt chứa truyền thừa bảo thuật Côn Bằng, khiến các thế lực trên tế đàn chém giết dữ dội để tranh đoạt.","detail":"Bảo cốt Côn Bằng là vật chứa truyền thừa bảo thuật Côn Bằng. Trong chương này, sáu miếng cốt lần lượt bị các thế lực đoạt được và chia cắt, mỗi phe cùng lắm giữ một miếng. Một miếng rơi vào tay bộ tộc Hỏa Viêm Ngư, một miếng bị Hàn Thiên dùng Thần Chiếu Đăng thu lấy, một miếng do sinh linh thuộc Thái Cổ Thần Sơn cướp được; Mạc Thương từng giữ một miếng nhưng bị vây công đến mức phải ném ra để tránh thoát. Các miếng cốt còn có giá trị đủ lớn để đem đổi với Tôn Giả lấy bảo vật vô giá.","nguon":["@c0262"]},{"id":"chan-huyet-con-bang","name":"Chân huyết Côn Bằng","cn":"","category":"nguyen-lieu","categoryLabel":"Chân huyết","phamCap":"Di huyết Côn Bằng","soHuu":["Thạch Hạo"],"trangThai":"Đã giúp Thạch Hạo phạt cốt tẩy tủy trong Hóa Ma động","blurb":"Một giọt chân huyết Côn Bằng ẩn trong ao máu linh tuyền, được Côn Bằng lưu lại cho người thừa kế dùng phạt cốt tẩy tủy.","detail":"Chân huyết Côn Bằng là một giọt huyết cực kỳ quý giá ẩn trong ao máu linh tuyền. Nó hòa vào ao máu, được lưu lại cho người thừa kế nhằm phạt cốt tẩy tủy. Thạch Hạo sau đại chiến trên tế đàn vốn thân thể rách nát, suýt chết; nhờ giọt chân huyết này mà hồi phục hoàn hảo, không còn vết sẹo, thân thể thoát thai hoán cốt và tiến thêm một bước.","nguon":["@c0262"]},{"id":"luong-thien-xich-mau-den","name":"Lượng Thiên Xích màu đen","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Không rõ","soHuu":[],"trangThai":"Chìm vào đại dương khi hang ổ Côn Bằng sụp xuống","blurb":"Một thần khí màu đen xuất hiện khi hang ổ Côn Bằng nứt sụp, sau đó bay lên rồi chìm vào đáy biển biến mất.","detail":"Lượng Thiên Xích màu đen là một trong các thần khí xuất hiện cùng Thiên Hoang, cây quạt màu vàng và chủy thủ Long Nha khi hang ổ Côn Bằng tan nát. Các thần khí này bay vút lên rồi chìm vào đại dương mênh mông, từ đó mất tăm. Do cấm chế dưới đáy biển chưa biến mất, ngay cả Tôn Giả cũng không dám tiến vào tìm kiếm.","nguon":["@c0262"]},{"id":"vien-than-dan-cua-thach-trung-thien","name":"Viên thần đan của Thạch Trung Thiên","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thần đan","soHuu":["Thạch Trung Thiên"],"trangThai":"đang có","blurb":"Viên thần đan mà Thạch Trung Thiên tìm được trong thời gian gặp nạn. Ông muốn dùng nó để bù đắp cho Hạo nhi sau khi không thể mang thuần huyết trở về.","detail":"Khi thoát khỏi cấm địa rừng đen, Thạch Trung Thiên nói năm xưa vào chiến trường bách tộc tìm thuần huyết cho cháu nhưng gặp nạn. Hiện ông có một viên thần đan và xem đó là thứ có thể bù đắp cho Hạo nhi.","nguon":["@c0263"]},{"id":"cung-lon-cua-dai-ma-than","name":"Cung lớn của Đại Ma Thần","cn":"","aliases":["Cung lớn của ông lão cụt tay","Cung lớn của Thập Ngũ gia"],"category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Thạch Trung Thiên"],"trangThai":"đang có","blurb":"Chiếc cung lớn mà Thạch Trung Thiên mang theo khi thoát khỏi cấm địa rừng đen. Vật này gắn với dáng vẻ thần võ, tàn tạ nhưng vẫn đáng sợ của ông.","detail":"Sau nhiều năm bị nhốt trong rừng sâu màu đen, Thạch Trung Thiên cụt tay, toàn thân đẫm máu nhưng vẫn mang theo một chiếc cung lớn khi xông ra ngoài.","nguon":["@c0263"]},{"id":"binh-chan-huyet-ty-nguu","name":"Bình chân huyết Tỳ Ngưu","category":"nguyen-lieu","categoryLabel":"Nguyên liệu / Huyết dịch","soHuu":["Thập Ngũ Gia"],"trangThai":"dang-co","blurb":"Bình ngọc chứa huyết dịch màu bạc rực rỡ, chân huyết của Tỳ Ngưu, do Thập Ngũ gia chiếm được rồi giấu trong đầm lầy nhiều năm.","detail":"Bình ngọc chứa huyết dịch màu bạc rực rỡ — chân huyết Tỳ Ngưu mà Thập Ngũ gia năm xưa chiếm được, giấu trong khu đầm lầy u ám ở Đại Hoang để thoát khỏi con Tỳ Hưu trưởng thành. Khi thu hồi, do để lâu không xử lý cẩn thận nên đã tản mất một chút linh tính, tinh hoa thần tính giảm bớt. Thập Ngũ gia định làm lễ vật tặng cho tôn nhi Thạch Hạo.","nguon":["@c0264"]},{"id":"te-dan-nho-truyen-tin","name":"Tế đàn nhỏ truyền tin","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Võ Vương phủ"],"trangThai":"dang-co","blurb":"Tế đàn nhỏ cao một thước đặt trên cửa thành lầu Hoàng Đô và trong Võ Vương phủ, dùng để truyền tin nhanh.","detail":"Viết chữ lên giấy rồi thả lên tế đàn, thần văn lóe sáng tạo thành thông đạo màu bạc để truyền tin nhanh về gia tộc. Các chiến tướng Võ Vương phủ và Vũ tộc dùng nó để báo tin Đại Ma Thần trở về.","nguon":["@c0265"]},{"id":"the-tu-phu","name":"Thế Tử phù","category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Vật nghịch thiên","soHuu":["Thạch Lạp"],"trangThai":"da-dung","blurb":"Phù bảo nghịch thiên cho phép giả chết/tự bạo hóa thành mưa sáng để thoát thân.","detail":"Thạch Lạp dùng Thế Tử phù để giả chết, tự bạo hóa thành mưa sáng mà thoát khỏi tay Thập Ngũ gia; Thập Ngũ gia nhận xét trong phủ cũng không có nhiều tấm phù như thế.","nguon":["@c0266"]},{"id":"chin-cay-co-lon","name":"Chín cây cờ lớn","category":"phap-bao","categoryLabel":"Trận kỳ","phamCap":"Không rõ","soHuu":["Thạch Trung Thiên"],"trangThai":"dang-co","blurb":"Chín lá cờ dùng để niêm phong bốn phía một tòa phủ đệ, chặn mọi người rời đi.","detail":"Thập Ngũ gia ném ra chín cây cờ lớn để niêm phong bốn phía Võ Vương phủ, phong bế toàn phủ và tuyên bố không ai được rời đi.","nguon":["@c0266"]},{"id":"the-menh-phu","name":"Thế Mệnh phù","aliases":["Thế Mệnh phù"],"category":"phap-bao","categoryLabel":"Phù bảo","phamCap":"Không rõ","soHuu":["Thạch Lạp"],"trangThai":"dang-co","blurb":"Loại phù liên quan sinh mệnh mà Thạch Lạp nắm giữ; Thập Ngũ gia bắt dùng cho hết, chỉ còn một tấm.","detail":"Thập Ngũ gia hỏi về Thế Mệnh phù, Thạch Lạp khai chỉ còn lại một tấm.","nguon":["@c0267"]},{"id":"lu-dong-kim-o","name":"Lư đồng Kim Ô","aliases":["Lư đồng của Võ Vương","Lư đồng của ông lão cụt tay"],"category":"than-khi","categoryLabel":"Thượng Cổ pháp khí","phamCap":"Thượng Cổ","soHuu":["Võ Vương"],"trangThai":"dang-co","blurb":"Chiếc lư đồng loang lổ gỉ xanh của Võ Vương, có thể dung hợp với bàn tay biến thế giới lòng bàn tay thành lò lửa luyện hóa địch.","detail":"Chiếc lư đồng loang lổ gỉ xanh, có thể dung hợp với bàn tay của Võ Vương, biến thế giới lòng bàn tay thành lò lửa luyện hóa địch và sau đó lơ lửng trên đầu hắn chảy thác nước thần hộ thân. Về sau lộ chân hình với đồ án Kim Ô.","nguon":["@c0270"]},{"id":"huyet-dan","name":"Huyết đan","aliases":[],"category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Thạch Trung Thiên"],"trangThai":"dang-co","blurb":"Viên đan Thập Ngũ gia dùng phù văn hóa đỉnh luyện hồ máu của Võ Vương thành, tỏa ánh lửa, xem như chế nhạo đối thủ.","detail":"Thập Ngũ gia dùng phù văn hóa đỉnh luyện hồ máu của Võ Vương thành một viên đan tỏa ánh lửa, công khai chế nhạo là bảo dược huyết nhục.","nguon":["@c0271"]},{"id":"than-vat-phat-sang-cua-vu-vuong","name":"Thần vật phát sáng của Vũ Vương","aliases":[],"category":"than-khi","categoryLabel":"Thần vật","phamCap":"Liên quan Thần Linh","soHuu":["Vũ Vương"],"trangThai":"dang-co","blurb":"Vật phát sáng chói mắt Vũ Vương lấy ra chặn thần tiễn của Đại Ma Thần, bị nhận định có quan hệ với Thần Linh.","detail":"Vũ Vương dùng thần vật phát sáng để chặn thần tiễn của Đại Ma Thần, dù vẫn bị đánh bay mấy trăm trượng; Thập Ngũ gia nghiêm túc nhận định vật này có quan hệ với Thần Linh.","nguon":["@c0272"]},{"id":"vu-than-phap-chi","name":"Vũ Thần pháp chỉ","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"di vật Thượng Cổ Thần Linh","soHuu":["Vũ tộc","Vũ Vương"],"trangThai":"bị phá vỡ trong trận với Đại Ma Thần","blurb":"Vũ Thần pháp chỉ là pháp chỉ do Thượng Cổ Thần Linh của Vũ tộc lưu lại. Khi được thức tỉnh, nó hóa thành các tấm hoàng kim mang ý chí sát phạt và trấn áp cả chiến trường.","detail":"Vũ Vương dùng nghi thức tế tự, tiếp dẫn sức mạnh sinh ra trong trận chiến để thức tỉnh mảnh vỡ pháp chỉ phát sáng. Pháp chỉ khắc chữ Phù, tỏa uy áp khiến mọi người quỳ rạp, làm Đại Ma Thần rơi khỏi không trung và chảy máu khóe miệng. Sau đó Thạch Trung Thiên dùng mũi tên Thượng Cổ Thần Linh bắn phá nhiều tấm pháp chỉ, khiến Vũ Vương kinh sợ định bỏ chạy.","nguon":["@c0274"]},{"id":"chin-chiec-ho-lo","name":"Chín chiếc hồ lô","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"trận nhãn sát phạt","soHuu":["Vũ Vương","Vũ tộc"],"trangThai":"bị phá vỡ","blurb":"Chín chiếc hồ lô là pháp bảo màu đỏ tươi xuất hiện trong Đại trận mưa máu của Vũ Vương. Chúng phun ánh kiếm, khiến uy lực trận pháp tăng vọt.","detail":"Chín hồ lô nhỏ lơ lửng trong màn mưa máu, miệng hồ lô phun ánh kiếm hóa thành sóng biển đỏ đậm. Khi bị Đại Ma Thần phá trận, chúng bốc cháy rồi nổ tung thành mảnh vỡ, cuối cùng bị Tay thần đánh tan thành bụi trần.","nguon":["@c0274"]},{"id":"mui-ten-thuong-co-than-linh","name":"Mũi tên Thượng Cổ Thần Linh","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"mũi tên Thượng Cổ Thần Linh lưu lại","soHuu":["Thạch Trung Thiên"],"trangThai":"đã dùng trong trận với Vũ Vương","blurb":"Mũi tên Thượng Cổ Thần Linh là mũi tên gần trong suốt, ánh bạc nhạt do Đại Ma Thần bắn ra từ cung lớn. Nó có sát khí ngập trời và đủ sức phá Vũ Thần pháp chỉ.","detail":"Thạch Trung Thiên kéo cung lớn, phun tia sáng hóa thành mũi tên ánh bạc. Mũi tên đầu bắn vỡ nhiều tấm pháp chỉ hoàng kim; mũi tên bạc thứ hai khiến pháp chỉ nổ tung, buộc Vũ Vương rơi vào thế tuyệt vọng.","nguon":["@c0274"]},{"id":"mui-ten-trang-den-xen-ke","name":"Mũi tên trắng đen xen kẽ","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"Không rõ","soHuu":["Thạch Trung Thiên"],"trangThai":"dang-co","blurb":"Mũi tên được Đại Ma Thần đặt lên dây cung khi áp sát Vũ Vương phủ. Nó được dùng bắn nổ đại môn và nhiều sân phủ.","detail":"Mũi tên trắng đen xen kẽ là một trong những mũi tên Đại Ma Thần dùng trong đợt công phạt Vũ tộc. Dưới uy lực của nó, đại môn, sân và phù văn phòng hộ của Vũ Vương phủ liên tiếp bị phá, khiến khu ngoài phủ biến thành phế tích.","nguon":["@c0275"]},{"id":"tuong-da-vu-than","name":"Tượng đá Vũ Thần","cn":"","category":"khac","categoryLabel":"Vật thờ/thần vật","phamCap":"Không rõ","soHuu":["Vũ tộc"],"trangThai":"dang-co","blurb":"Tượng đá Vũ Thần nằm trong thần miếu Vũ tộc. Sau khi thần miếu sụp đổ, tượng đá cùng tế đàn phát ánh sáng đáng sợ và tạo tràng vực phong tỏa phủ đệ.","detail":"Tượng đá Vũ Thần là trung tâm tế bái trong cấm địa Vũ tộc. Khi thần miếu bị tên thần của Đại Ma Thần bắn tới sụp đổ, tượng đá vẫn còn lại, tỏa ánh sáng bất thường cùng tế đàn và góp phần hình thành tràng vực niêm phong cả tòa phủ đệ.","nguon":["@c0275"]},{"id":"te-dan-vu-toc","name":"Tế đàn Vũ tộc","cn":"","category":"khac","categoryLabel":"Vật thờ/trận cơ","phamCap":"Không rõ","soHuu":["Vũ tộc"],"trangThai":"dang-co","blurb":"Tế đàn còn lại trong thần miếu Vũ tộc sau khi nơi này sụp đổ. Nó cùng tượng đá phát ánh sáng bất thường, hình thành tràng vực niêm phong phủ đệ.","detail":"Tế đàn Vũ tộc xuất hiện cùng tượng đá Vũ Thần ở phần sâu nhất của phủ. Sau khi thần miếu bị phá, tế đàn vẫn tỏa ánh sáng đáng sợ và trở thành một phần của tràng vực khiến Đại Ma Thần không tiến vào thần thổ Vũ tộc.","nguon":["@c0275"]},{"id":"bao-thap-cua-bong-nguoi-cuoi-chuong","name":"Bảo tháp của bóng người cuối chương","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Bóng người cầm bảo tháp"],"trangThai":"dang-co","blurb":"Tòa bảo tháp được nhân vật bí ẩn cầm khi xuất hiện trên đường chính Hoàng Đô. Chương này chưa nêu lai lịch hay công năng của nó.","detail":"Bảo tháp xuất hiện ở cuối chương, trong tay một bóng người cao lớn đi tới trên đường chính Hoàng Đô. Sự xuất hiện của pháp bảo này diễn ra ngay sau khi Đại Ma Thần ép Vũ tộc chịu nhục, báo hiệu khả năng có biến cố tiếp theo.","nguon":["@c0275"]},{"id":"thap-dong-phap-khi-than-linh","name":"Tháp đồng Pháp khí Thần Linh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí Thần Linh","soHuu":["Bích Ma Hắc Đồng Chu"],"trangThai":"đang sử dụng @c0276","blurb":"Chiếc tháp đồng của người tóc xanh, được Đại Ma Thần nhận ra là Pháp khí Thần Linh.","detail":"Tháp đồng thau mang vết tích năm tháng hóa thành phù văn, có thể hóa lớn như ngọn núi và phóng thích uy năng trấn áp cả Võ Vương phủ. Khi người tóc xanh hô thu, tháp có thể hút người vào trong; Thạch Trung Thiên từng đánh mất chiếc tháp này và bị hút vào tháp trong trận chiến, sau đó giết thoát ra ngoài.","nguon":["@c0276"]},{"id":"tam-khoi-cot-phong-an","name":"Tám khối cốt phong ấn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"không rõ","soHuu":["Bích Ma Hắc Đồng Chu"],"trangThai":"đã dùng @c0276","blurb":"Tám khối cốt nhiều màu dùng để phong ấn Võ Vương phủ.","detail":"Người tóc xanh lấy ra tám khối cốt màu sắc khác nhau, gồm tím, trắng bóng và vàng óng, tỏa mây khí lạnh. Hắn rung tay cho chúng bay ra tám hướng để niêm phong hoàn toàn Võ Vương phủ, ngăn Thạch Trung Thiên đào tẩu.","nguon":["@c0276"]},{"id":"mui-ten-bac-va-mui-ten-den","name":"Mũi tên bạc và mũi tên đen","cn":"","category":"phap-bao","categoryLabel":"Vũ khí","phamCap":"không rõ","soHuu":["Thạch Trung Thiên"],"trangThai":"đang sử dụng @c0276","blurb":"Hai mũi tên thần được Thạch Trung Thiên dùng để công kích tháp đồng.","detail":"Trong trận với người tóc xanh, Thạch Trung Thiên dùng mũi tên màu bạc xuyên hư không đánh tháp đồng nhưng không thể bắn thủng. Khi bị hút vào tháp, ông tiếp tục bắn thêm mũi tên thần màu đen, trong lúc mũi tên bạc bên ngoài tự chủ công kích thân tháp.","nguon":["@c0276"]},{"id":"bao-cot-mau-tim","name":"Bảo cốt màu tím","cn":"","category":"nguyen-lieu","categoryLabel":"Vật phẩm trận cơ","phamCap":"không rõ","soHuu":["Bích Ma Hắc Đồng Chu"],"trangThai":"không rõ","blurb":"Khối bảo cốt được dùng làm trận cơ trấn áp Thạch Trung Thiên.","detail":"Trong lúc Thạch Trung Thiên lùi gần vùng phong ấn, một khối bảo cốt màu tím bất ngờ vọt lên để trấn áp ông, là một phần của sát trận do Bích Ma Hắc Đồng Chu bố trí.","nguon":["@c0277"]},{"id":"tam-da-thu-tran-do","name":"Tấm da thú trận đồ","cn":"","category":"phap-bao","categoryLabel":"Trận đồ","phamCap":"không rõ","soHuu":["Thạch Trung Thiên"],"trangThai":"đang sử dụng","blurb":"Tấm da thú được Thạch Trung Thiên dùng để lập trận đối kháng Ma Chu.","detail":"Thạch Trung Thiên tung tấm da thú xoay tròn, phối hợp các khối bảo cốt kích phát kiếm khí, nhờ đó chống lại sát trận phù cốt của Bích Ma Hắc Đồng Chu.","nguon":["@c0277"]},{"id":"thuyen-u-linh","name":"Thuyền U Linh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo di chuyển","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"đang được sử dụng","blurb":"Chiếc thuyền Thạch Hạo dùng vượt Bắc Hải để trở về đất liền sau hai năm lưu lạc hải ngoại.","detail":"Thuyền U Linh di chuyển trên biển, đưa Thạch Hạo và Bóng Lông trở về từ Bắc Hải. Khi Thạch Hạo lặn xuống đáy biển thăm dò thành trì Nhân Ngư, chiếc thuyền có thể được thu lại.","nguon":["@c0278"]},{"id":"huyet-tinh-chau","name":"Huyết tinh châu","cn":"","category":"nguyen-lieu","categoryLabel":"Vật liệu luyện dược","phamCap":"Quý hiếm","soHuu":["Thạch Hạo","Nhân Ngư Tộc"],"trangThai":"được tặng cho Thạch Hạo","blurb":"Trân châu đỏ máu hình thành từ con trai có đạo hạnh cao thâm, chứa thần năng tinh thuần.","detail":"Huyết tinh châu do con trai đạo hạnh cao hun đúc huyết nhục tinh khí mà thành. Vật này có thể luyện thành Huyết đan, khi luyện dược thêm bột phấn còn có thể tăng dược tính, được cô gái Nhân Ngư Tộc tặng cho Thạch Hạo.","nguon":["@c0278"]},{"id":"hai-lam-tuy","name":"Hải Lam Tủy","cn":"","aliases":["Hải Lam Thạch"],"category":"nguyen-lieu","categoryLabel":"Vật liệu luyện khí","phamCap":"Quý hiếm","soHuu":["Thạch Hạo","Nhân Ngư Tộc"],"trangThai":"da-dung","blurb":"Tinh thạch xanh lam dưới đáy biển, dùng để luyện bảo cụ và tăng uy năng pháp khí.","detail":"Hải Lam Tủy là vật liệu luyện khí quý báu trong thành trì Nhân Ngư, khiến các thế lực lớn cũng động tâm. Cô gái Nhân Ngư Tộc tặng vật này cho Thạch Hạo để đền ơn.","nguon":["@c0278","@c0282","@c0284"]},{"id":"doan-canh-cay-lieu-than","name":"Đoạn cành cây Liễu Thần","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Đoạn cành xanh mơn mởn Liễu Thần cho Thạch Hạo, nó mang theo hơn hai năm.","detail":"Đoạn cành xanh mơn mởn mà Thạch Hạo chưa dùng tới, định trả lại nhưng Liễu Thần bảo cứ giữ trên người.","nguon":["@c0279"]},{"id":"ngoc-bich-than","name":"Ngọc bích thần","cn":"","aliases":["thần bích"],"category":"khac","categoryLabel":"Vật phẩm thần bí","phamCap":"Siêu phàm","soHuu":["Hồ Ly Tinh áo trắng"],"trangThai":"đang trong điện phủ của Hồ Ly Tinh áo trắng","blurb":"Khối thần bích trong điện phủ của Hồ Ly Tinh áo trắng, phát sáng khi Thạch Hạo xuất hiện. Tiểu tháp xác nhận đây là vật siêu phàm mà nó cần.","detail":"Ngọc bích thần có khả năng cảm ứng tiềm năng kinh người, khiến Hồ Ly Tinh áo trắng nhận ra Thạch Hạo có thể trở thành một trong các bá chủ Hoang Vực. Tiểu tháp từng nói nếu có đủ bốn khối ngọc bích thần thì sẽ cho Thạch Hạo một cơ hội sử dụng, nên khối thần bích này trở thành vật then chốt được Thạch Hạo chú ý.","nguon":["@c0280"]},{"id":"than-bich-vat-lieu","name":"Thần bích","category":"nguyen-lieu","categoryLabel":"Nguyên liệu / Kỳ trân","trangThai":"dang-co","soHuu":[],"blurb":"Vật liệu kỳ trân từng được tiểu tháp cảm ứng ở Hoàng Đô, ví dụ cho việc nơi này có dị bảo có thể trao đổi.","detail":"Một loại vật liệu quý mà tiểu tháp của Thạch Hạo từng cảm ứng được mấy ngày trước tại Hoàng Đô, minh chứng cho việc Hoàng Đô có kỳ trân dị bảo đủ để đổi lấy thêm lần xuất thủ của tiểu tháp.","nguon":["@c0281"]},{"id":"than-huyet-te-linh-luu-lai","name":"Thần huyết Tế Linh lưu lại","category":"khac","categoryLabel":"Thần huyết / Truyền thừa","trangThai":"dang-co","soHuu":["Nhân Hoàng"],"blurb":"Thần huyết Tế Linh do Hoàng thất Thạch Quốc lưu giữ, được Thạch Tử Đằng xin để tẩy thân thể cho Thạch Nghị.","detail":"Thứ thần huyết truyền thừa của Tế Linh do Nhân Hoàng lưu giữ; Thạch Tử Đằng đề nghị Nhân Hoàng lấy ra để tẩy thân thể cho Thạch Nghị, khiến các vương hầu chấn động vì hàm ý chính trị về vấn đề kế thừa.","nguon":["@c0281"]},{"id":"thien-cot-khoi-ky-cot-trang","name":"Thiên cốt","cn":"","aliases":["Khối kỳ cốt trắng sáng"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ (@c0282)","soHuu":[],"trangThai":"dang-co","blurb":"Vật phẩm đầu tiên của buổi đấu giá Cốt Cổ, khối cốt trắng sáng cực giống Nguyên Thủy Chân Giải khiến Thạch Hạo chấn động.","detail":"Khối cốt trắng sáng được đưa ra làm vật đấu giá mở màn, khí thế và chất liệu rất giống Nguyên Thủy Chân Giải. Lão giả chủ trì gọi đó là Thiên cốt, cứng rắn hiếm thấy, không thể phá hủy bằng mọi biện pháp đã thử, khiến toàn trường náo động và Thạch Hạo quyết tâm mua bằng được.","nguon":["@c0282"]},{"id":"huyet-ma-thuoc","name":"Huyết Ma Thước","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (@c0282)","soHuu":[],"trangThai":"dang-co","blurb":"Vật phẩm đấu giá là mục tiêu khiến Hỗn Thiên hầu tới phòng đấu giá Cốt Cổ; chương này chưa mô tả hình dạng hay công dụng.","detail":"Hỗn Thiên hầu trực tiếp nói chỉ vì thanh Huyết Ma Thước mà đến phòng đấu giá Cốt Cổ, báo trước vật này có giá trị đủ hấp dẫn một vương hầu trẻ họ Thạch.","nguon":["@c0282"]},{"id":"chien-xa-hoang-kim-hon-thien-hau","name":"Chiến xa hoàng kim của Hỗn Thiên hầu","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (@c0282)","soHuu":["Hỗn Thiên hầu"],"trangThai":"dang-co","blurb":"Chiến xa hoàng kim do tám hung thú kéo, có ấn ký được người trong Hoàng Đô nhận ra là của Hỗn Thiên hầu.","detail":"Xe do tám hung thú kéo lao tới phòng đấu giá Cốt Cổ, mang ấn ký biểu thị thân phận vương hầu, khiến đám đông chú ý và nhận ra chủ nhân là Hỗn Thiên hầu.","nguon":["@c0282"]},{"id":"bo-hai-cot-nhai-ti","name":"Bộ hài cốt Nhai Tí","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ (@c0282)","soHuu":[],"trangThai":"dang-co","blurb":"Bộ xương hung thú Nhai Tí màu vàng khổng lồ được trưng bày ở đại sảnh phòng đấu giá Cốt Cổ.","detail":"Bộ xương màu vàng cao hơn mười trượng, dài hơn hai mươi đến ba mươi trượng, không phải Nhai Tí thuần huyết nhưng còn nguyên thủy phù cốt lưu chuyển thần lực cho cả tòa nhà, được trưng bày thay vì luyện thành pháp khí, cho thấy nội tình hùng hậu của phòng đấu giá.","nguon":["@c0282"]},{"id":"long-cot-thiet","name":"Long Cốt Thiết","cn":"","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"thần liệu luyện khí","soHuu":["Đại tiểu thư Lôi tộc"],"trangThai":"được đưa ra đấu giá","blurb":"Long Cốt Thiết là thần liệu do Chân Long vẫn lạc trên quặng sắt mà hình thành. Đại tiểu thư Lôi tộc đưa ra một khối bằng đốt ngón tay để tranh khối tàn cốt Thiên Cốt.","detail":"Giám định sư nhận định đây là tài liệu thần cấp luyện khí của chư thánh, nếu đủ nhiều có thể luyện thành thần khí. Trong buổi đấu giá, giá trị của nó vẫn không vượt được khối Hải Lam Tủy cực lớn do Thạch Hạo đưa ra.","nguon":["@c0283"]},{"id":"phuong-thuoc-to-truyen-thach-thon","name":"Phương thuốc tổ truyền Thạch Thôn","cn":"","aliases":[],"category":"dan-duoc","categoryLabel":"Phương thuốc","phamCap":"phương tẩy tủy tráng cốt","soHuu":["Thạch Hạo","Thạch Thôn"],"trangThai":"đã dùng để trao đổi","blurb":"Phương thuốc tổ truyền Thạch Thôn gồm các phương tẩy tủy tráng cốt, bảo trì huyết khí cường thịnh. Thạch Hạo viết vài phương đơn giản để đổi lấy Bảo thuật Huyền Quy.","detail":"Người bán mai rùa Huyền Quy chỉ muốn đổi lấy phương thuốc giúp tẩy tủy, tráng cốt và giữ huyết khí. Thạch Hạo lấy truyền thừa dược phương của Thạch Thôn làm giá, cuối cùng được chọn và đoạt được bảo thuật phòng ngự.","nguon":["@c0283"]},{"id":"ti-hoa-chau","name":"Tị Hỏa Châu","category":"khac","categoryLabel":"Kỳ châu","phamCap":"Chí bảo","soHuu":["Thập Lục công chúa"],"trangThai":"dang-co","blurb":"Viên châu đỏ thẫm như hồng ngọc, lớn như trứng bồ câu, kháng hỏa cực mạnh.","detail":"Kỳ châu đỏ thẫm lớn như trứng bồ câu, có vết nứt và tróc một miếng. Kháng hỏa, dùng để xâm nhập cấm địa dung nham hỏa diễm hay thần hỏa, làm thần liệu luyện chế Thánh khí, Thần khí. Cực kỳ quý hiếm, được xác định là chí bảo. Trên hội đấu giá bị Thập Lục công chúa đoạt bằng một đống nguyên thủy phù cốt.","nguon":["@c0284"]},{"id":"dinh-phong-chau","name":"Định Phong Châu","category":"khac","categoryLabel":"Kỳ châu","phamCap":"Cực hiếm","soHuu":[],"trangThai":"dang-co","blurb":"Kỳ châu cùng loại với Tị Hỏa Châu, cực kỳ quý hiếm.","detail":"Được nhắc cùng loại với Tị Hỏa Châu, thuộc hàng kỳ châu cực hiếm.","nguon":["@c0284"]},{"id":"da-hu-khong-thu","name":"Da Hư Không Thú","category":"nguyen-lieu","categoryLabel":"Tài liệu","phamCap":"Cực hiếm","soHuu":[],"trangThai":"dang-co","blurb":"Tấm da thú ảm đạm giúp nấp trong hư vô, tế luyện có thể xuyên hư không.","detail":"Tấm da thú ảm đạm khoảng một mét vuông, giúp người nấp trong hư vô không thể dò xét, tế luyện có thể xuyên hư không. Cực hiếm; Nhân Hoàng Hỏa Quốc từng có bản lớn hơn làm pháp khí quốc gia, Thạch Hạo từng thấy Hỏa Linh Nhi lấy ra ở Bách Đoạn Sơn. Trên hội đấu giá rơi vào tay một người thần bí trốn trong gian khách quý.","nguon":["@c0284"]},{"id":"thien-ma-tan","name":"Thiên Ma Tán","category":"phap-bao","categoryLabel":"Binh khí","phamCap":"Cấp vương hầu","soHuu":[],"trangThai":"dang-co","blurb":"Binh khí lấp lánh ô quang, âm khí dày đặc, trân phẩm cấp vương hầu.","detail":"Binh khí lấp lánh ô quang, âm khí dày đặc, thuộc hàng trân phẩm cấp vương hầu, trên hội đấu giá được một Vương gia lấy đi.","nguon":["@c0284"]},{"id":"tieu-nhan-den-chien-ngau-thuong-co","name":"Tiểu nhân đen","cn":"","category":"phap-bao","categoryLabel":"Chiến ngẫu","phamCap":"Chí bảo (hư hỏng)","soHuu":[],"trangThai":"dang-co","blurb":"Tiểu nhân màu đen nhỏ như nắm đấm, nghi là chiến ngẫu chí cường Thượng Cổ hư hỏng, được tiểu tháp khẳng định là chí bảo.","detail":"Pháp khí Thượng Cổ nhỏ như nắm đấm, kim loại ảm đạm không ánh sáng, phù văn tổn hại nứt nẻ, cầm thấy nặng và lạnh như băng. Nghi là chiến ngẫu chí cường bị hư hỏng nên mọi người coi như phế bảo, nhưng tiểu tháp khẳng định đủ hưởng thụ cả đời, thậm chí tiếc không nỡ tiêu hóa — là chí bảo nhân gian.","nguon":["@c0284"]},{"id":"dia-tuy","name":"Địa tủy","category":"nguyen-lieu","categoryLabel":"Vật liệu","phamCap":"Quý hiếm","soHuu":[],"trangThai":"dang-co","blurb":"Vật liệu được xưng có thể kéo dài sinh mệnh.","detail":"Có người lấy ra một khối lớn trên hội đấu giá, được xưng có thể kéo dài sinh mệnh.","nguon":["@c0284"]},{"id":"lam-linh-tho-tu-linh-dang","name":"Lam Linh Thổ và Tử Linh Đẳng","category":"nguyen-lieu","categoryLabel":"Tài liệu","phamCap":"Hi hữu","soHuu":[],"trangThai":"dang-co","blurb":"Trong hơn mười loại tài liệu hi hữu được đấu giá, giá trị kinh người.","detail":"Nằm trong hơn mười loại tài liệu hi hữu được đưa ra đấu giá trên hội, giá trị kinh người.","nguon":["@c0284"]},{"id":"khoi-tai-lieu-khong-luu-chut-bui-ban","name":"Khối tài liệu không lưu chút bụi bẩn","cn":"","aliases":["Tài liệu cổ không dính bụi"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"không rõ","soHuu":["Thạch Hạo"],"trangThai":"Thạch Hạo mua được tại đấu giá hội","blurb":"Khối tài liệu cổ được đào từ phế tích, bề ngoài không dính chút bụi bẩn. Người trong đấu giá hội xem nhẹ vì tưởng thần tính đã mất, nhưng Tiểu tháp cho biết nó có thể giúp Tiểu tháp thêm nửa lần xuất thủ.","detail":"Vật này được đưa ra sau biến cố Bất Diệt Kim Thân tại Phòng đấu giá Cốt Cổ. Dù giá trị bị đánh thấp, Thạch Hạo mua được sau khi nghe Tiểu tháp chỉ điểm; công dụng được nêu trực tiếp là có thể đổi lấy nửa lần xuất thủ của Tiểu tháp.","nguon":["@c0285"]},{"id":"nhan-cau-trung-dong-gia","name":"Nhãn cầu Trùng Đồng giả","cn":"","aliases":["Hạt châu dính vết máu đen","Trùng Đồng nhãn cầu Thượng Cổ","Trùng Đồng"],"category":"phap-bao","categoryLabel":"Thần vật","phamCap":"thần nhân chí tôn Thượng Cổ","soHuu":[],"trangThai":"đang được tranh đoạt tại Phòng đấu giá Cốt Cổ","blurb":"Nhãn cầu Trùng Đồng giả xuất hiện dưới dạng hạt châu lớn như nắm đấm, có vết nứt và dính máu đen. Hai nữ tử từng giám định rồi bỏ qua, nhưng Tiểu tháp nhận ra bên trong là con mắt có nguồn gốc từ một vị Trùng Đồng giả.","detail":"Món này xuất hiện ở cuối đấu giá hội, bị đánh giá là đã hỏng vì vết máu đen và vết nứt trên bề mặt. Tiểu tháp lại chỉ ra ma huyết chỉ như vết sẹo, còn bên trong là con mắt từ thần nhân chí tôn Thượng Cổ, liên hệ trực tiếp tới Trùng Đồng, khiến Thạch Hạo quyết định toàn lực tranh đoạt.","nguon":["@c0285"]},{"id":"thach-chau","name":"Thạch châu","cn":"","aliases":["Quả cầu đá"],"category":"khac","categoryLabel":"Vật chứa","phamCap":"thần bí","soHuu":["Thạch Hạo"],"trangThai":"đã bị bóc mở","blurb":"Viên đá nặng âm u bọc máu Thần Ma khô, che giấu Trùng Đồng Thượng Cổ bên trong.","detail":"Thạch châu cực kỳ cứng rắn, bên ngoài có vết máu Thần Ma đã khô và mất linh tính. Khi bị Thạch Hạo dùng kiếm gãy chém bóc từng lớp, bên trong lộ mũi tên đồng đen mục nát và cuối cùng là Trùng Đồng còn sinh cơ.","nguon":["@c0286"]},{"id":"mui-ten-dong-den","name":"Mũi tên đồng đen","cn":"","aliases":[],"category":"than-khi","categoryLabel":"Thần khí cổ","phamCap":"Thần linh pháp khí đã hủy","soHuu":[],"trangThai":"mục nát","blurb":"Mũi tên cổ nằm trong thạch châu, từng là thần khí nhưng đã bị hủy hoại.","detail":"Mũi tên đồng đen suýt đâm vào trung tâm thạch châu, năm xưa là pháp khí thần linh. Nó không thể thương tổn Trùng Đồng Thượng Cổ, ngược lại bản thân mục nát và bị hủy.","nguon":["@c0286"]},{"id":"mai-rua-huyen-quy","name":"Mai rùa Huyền Quy","cn":"","aliases":["Khối mai rùa Huyền Quy"],"category":"khac","categoryLabel":"Vật phẩm chứa bảo thuật","phamCap":"bảo vật đấu giá","soHuu":["Thạch Hạo"],"trangThai":"dang-co","blurb":"Mai rùa Huyền Quy là khối mai rùa ghi lại bảo thuật Huyền Quy mà Thạch Hạo lấy được từ hội đấu giá. Nó liên quan tới một con Huyền Quy Thái Cổ di chủng từng làm loạn ở Tây Cương Thạch Quốc.","detail":"Khối mai rùa chứa bảo thuật phòng ngự quý hiếm của Huyền Quy, một đời sau của Huyền Vũ với năng lực phòng ngự nổi bật. Thạch Hạo nghiên cứu vật này, sau đó ngồi trên bồ đoàn Côn Bằng để ngộ pháp, tu luyện ra hào quang vàng đất rồi chuyển đen, phù văn như sóng và cảnh tượng tựa Huyền Vũ sống lại.","nguon":["@c0287"]},{"id":"chien-xa-tam-hung-thu","name":"Chiến xa tám hung thú","cn":"","category":"phap-bao","categoryLabel":"Bảo xa","phamCap":"khong-ro","soHuu":["Thiếu niên chủ nhân chiến xa","Thạch Hạo"],"trangThai":"bị Thạch Hạo chiếm","blurb":"Chiến xa tám hung thú là bảo xa của một thiếu niên quý tộc tại Hoàng Đô. Xe do tám hung thú kéo, lao tới ép Thạch Hạo rồi trở thành chiến lợi phẩm của hắn.","detail":"Bảo xa xuất hiện trên đường tới Thanh Lâm viên, phu xe dùng nó để áp sát và hạch hỏi Thạch Hạo về Thiên Hồ tiên tử. Sau khi phu xe và nhóm thiếu niên bị đánh bại, Thạch Hạo tuyên bố chiếc xe thuộc về mình và nghênh ngang rời đi.","nguon":["@c0288"]},{"id":"bao-xa-vuong-hau-quy-toc","name":"Bảo xa vương hầu quý tộc","cn":"","aliases":["Thanh đồng xa","Chiến xa hoàng kim","Chiến xa màu bạc"],"category":"phap-bao","categoryLabel":"Bảo xa","phamCap":"khong-ro","soHuu":["Vương hầu quý tộc Hoàng Đô"],"trangThai":"đang lưu hành","blurb":"Bảo xa vương hầu quý tộc là loại chiến xa xuất hiện dày đặc tại Hoàng Đô trong dịp chúc thọ Nhân Hoàng. Chúng có thể là thanh đồng xa, chiến xa hoàng kim hoặc chiến xa màu bạc, thường do hung thú kéo.","detail":"Các chiến xa phủ phù văn, tỏa bảo huy, chạy ầm ầm trên đường đá Hoàng Đô và biểu thị thân phận của vương hầu quý tộc. Một vụ va chạm giữa thanh đồng xa và chiến xa bạc của Tử Uy Hầu phủ cho thấy kiểu xung đột công khai giữa các phủ đệ trong không khí lấy võ lập quốc.","nguon":["@c0288"]},{"id":"xe-keo-trong-suot-cua-thien-ho-tien-tu","name":"Xe kéo trong suốt của Thiên Hồ tiên tử","cn":"","category":"phap-bao","categoryLabel":"Bảo xa","phamCap":"khong-ro","soHuu":["Thiên Hồ tiên tử"],"trangThai":"đang dùng","blurb":"Xe kéo trong suốt của Thiên Hồ tiên tử là bảo xa lấp lánh do thụy thú kéo. Xe tạo sương mù mông lung, tôn lên khí chất mê hoặc của nữ tử Thiên Hồ tộc.","detail":"Thiên Hồ tiên tử và Tiểu Hồ Ly ngồi trên chiếc xe này khi gặp Thạch Hạo trên đường Hoàng Đô. Nàng dừng xe mời Thạch Hạo đi nhờ, nhưng hắn cảm thấy nàng nguy hiểm nên từ chối.","nguon":["@c0288"]},{"id":"chien-xa-thanh-dong-cua-lang-van-hau","name":"Chiến xa thanh đồng của Lăng Vân hầu","cn":"","aliases":["chiến xa thanh đồng"],"category":"phap-bao","categoryLabel":"Chiến xa","phamCap":"không rõ","soHuu":["Thạch Hạo","Lăng Vân hầu"],"trangThai":"Thạch Hạo tạm chiếm","blurb":"Chiến xa thanh đồng của Lăng Vân hầu là cỗ xe cổ được tám hung thú thông linh kéo. Thạch Hạo cướp được nó và lái thẳng vào Thanh Lâm viên.","detail":"Cỗ chiến xa có dáng cổ điển, khắc núi sông, chim muông, tinh tú và ngư trùng. Tám hung thú kéo xe đều có sát khí chiến trường và từng phản kháng khi đổi chủ, nhưng bị Thạch Hạo dùng Kim Sí Bằng Điểu áp chế.","nguon":["@c0289"]},{"id":"than-ma-huyet-xich","name":"Thần Ma Huyết Xích","cn":"","aliases":["Huyết Xích","Thước máu"],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"pháp khí hung danh từ Thượng Cổ","soHuu":["Hỗn Thiên hầu"],"trangThai":"đang thuộc Hỗn Thiên hầu","blurb":"Thần Ma Huyết Xích là thanh thước máu của Hỗn Thiên hầu, nổi danh hung lệ từ thời Thượng Cổ. Khi được tung ra bên hồ, nó khiến Chân Chấn phải cả kinh rút tay lại.","detail":"Pháp khí này xuất hiện trong cuộc đối đầu giữa Hỗn Thiên hầu và Chân Chấn tại lâm viên Hoàng Đô. Hỗn Thiên hầu điều động thước máu đâm lên không trung, khí thế đủ khiến đối thủ ngoài Hoàng Vực nhận ra hung danh Thượng Cổ của nó.","nguon":["@c0290"]},{"id":"than-ma-chien-vuc","name":"Thần Ma Chiến Vực","cn":"","category":"phap-bao","categoryLabel":"Chí bảo","phamCap":"Chí bảo","soHuu":[],"trangThai":"Đang được sử dụng","blurb":"Chí bảo biến hóa thành một không gian chiến đấu riêng, có thể áp chế tu vi của những người bên trong xuống cảnh giới được lựa chọn.","detail":"Thần Ma Chiến Vực mang dáng dấp một chiến trường thượng cổ mờ tối. Khi được dùng cho cuộc quyết đấu giữa Thạch Hạo và Nguyệt Thiền tiên tử, không gian này áp chế tu vi xuống Động Thiên cảnh.","nguon":["@c0291"]},{"id":"kiem-ngoc-cua-nguyet-thien","name":"Kiếm ngọc của Nguyệt Thiền","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Nghi Thượng Cổ Thánh Khí","soHuu":["Nguyệt Thiền tiên tử"],"trangThai":"Nguyên vẹn","blurb":"Thần kiếm dài hơn một xích, có khả năng phá không gian và chém đứt bảo cụ cấp vương hầu.","detail":"Nguyệt Thiền tiên tử dùng kiếm ngọc phá vỡ Thần Ma Chiến Vực, cắt đứt lưới ánh sao, đánh tan mây đen và chém chết kẻ tập kích cưỡi chim lớn. Việc thanh kiếm có phải Thượng Cổ Thánh Khí hay không mới chỉ là suy đoán của người quan sát.","nguon":["@c0293"]},{"id":"bao-cu-hinh-thai-duong-cua-thien-ho-tien-tu","name":"Bảo cụ hình thái dương của Thiên Hồ tiên tử","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thiên Hồ tiên tử"],"trangThai":"Nguyên vẹn","blurb":"Bảo cụ có thể hóa thành một vầng thái dương, chấn động trời cao và dẫn động sấm sét.","detail":"Thiên Hồ tiên tử sử dụng bảo cụ này để phối hợp phá lưới ánh sao và đánh tan mây đen. Uy lực còn nghiền nát phần thi thể còn lại của chim khổng lồ thành bột mịn.","nguon":["@c0293"]},{"id":"luoi-anh-sao-cap-vuong-hau","name":"Lưới ánh sao cấp vương hầu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Vương hầu","soHuu":["Kẻ cưỡi chim lớn phục vụ tiểu chủ nhân Thái Cổ Thần Sơn"],"trangThai":"Đã bị phá hủy","blurb":"Bảo cụ dạng lưới tỏa ánh sao, đủ sức bao phủ cả hồ lớn và bắt giữ nhiều mục tiêu.","detail":"Kẻ cưỡi chim lớn thả chiếc lưới từ trên trời xuống nhằm bắt Nguyệt Thiền tiên tử, Thiên Hồ tiên tử và Thạch Hạo. Lưới được ví như ngân hà đan thành nhưng bị kiếm ngọc cùng bảo cụ hình thái dương hợp lực phá hủy.","nguon":["@c0293"]},{"id":"khoi-xuong-than-bi","name":"Khối xương thần bí","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Được Thạch Hạo giữ lại","blurb":"Khối xương cổ được Thạch Hạo mua tại buổi đấu giá, nghi liên quan đến Nguyên Thủy Chân Giải và bí mật Thiên Cốt.","detail":"Một thiếu niên đồng hành với đại tiểu thư Lôi tộc từng đề nghị trả giá cao để mua lại khối xương nhưng bị từ chối. Thạch Hạo cho rằng vật này có khả năng là một phần khác của Nguyên Thủy Chân Giải, đồng thời chứa manh mối về Thiên Cốt.","nguon":["@c0293"]},{"id":"chuy-thu-lang-nha","name":"Chủy thủ Lang Nha","cn":"","category":"phap-bao","categoryLabel":"Cổ bảo hư hỏng","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Đã bị Tiểu tháp nuốt","blurb":"Cây chủy thủ gần đứt rời được bán lẫn trong một số cổ khí hư hỏng, thực chất do răng rồng con hóa thành.","detail":"Tiểu tháp cảm ứng được chủy thủ khi Thạch Hạo tới gần khu trưng bày cổ khí. Thạch Hạo mua món đồ với giá rẻ rồi mang tới nơi vắng người để Tiểu tháp nuốt, đổi lấy lời hứa được cứu thêm một lần.","nguon":["@c0293"]},{"id":"rang-rong-con","name":"Răng rồng con","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"Đã bị Tiểu tháp nuốt","blurb":"Vật liệu quý ẩn trong hình dạng Chủy thủ Lang Nha, được xác định là răng rồng con chứ không phải răng sói.","detail":"Tiểu tháp nhận ra bản chất thật của cây chủy thủ và phân biệt vật liệu này với răng Chân Long. Sau khi Thạch Hạo mua chủy thủ, chiếc răng đã bị Tiểu tháp nuốt để đổi lấy thêm một lần cứu mạng.","nguon":["@c0293"]},{"id":"chen-hoa-thien-hang-nhai-bi-tan-pha","name":"Chén Hóa Thiên hàng nhái bị tàn phá","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Hàng nhái","soHuu":["Thạch Hạo"],"trangThai":"Đã bị vỡ, được Thạch Hạo tế luyện","blurb":"Một Chén Hóa Thiên hàng nhái đã hư hại nhưng bên trong vẫn chứa vật liệu mang thần tính. Thạch Hạo dùng sáu viên Huyết Tinh Châu đổi lấy và nhanh chóng nắm được cách sử dụng.","detail":"Chiếc chén có thể thu nước và luyện hóa vật chất. Sau khi dùng nhãn cầu của trời sinh thần nhân quan sát, Thạch Hạo nhận ra thần hà cùng vật liệu thần tính ẩn bên trong, cho rằng có thể tinh luyện nó rồi bổ sung thần liệu để phục luyện thành Chén Hóa Thiên chân chính trong tương lai.","nguon":["@c0294"]},{"id":"chen-hoa-thien-thuong-co","name":"Chén Hóa Thiên Thượng Cổ","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"Bảo cụ Thượng Cổ","soHuu":[],"trangThai":"Chỉ được nhắc tới","blurb":"Bảo cụ nổi danh thời Thượng Cổ, từng được đặt ngang hàng với túi càn khôn. Phiên bản nổi danh nhất có uy lực đủ tiêu diệt Thiên Thần.","detail":"Chén được luyện từ những thần liệu cực kỳ quý hiếm như Tinh Thần Sa và Thần Huyết, có khả năng dung luyện chư thiên vạn vật thành một lò. Đây là nguyên bản khác với chiếc chén hàng nhái bị tàn phá mà Thạch Hạo thu được.","nguon":["@c0294"]},{"id":"nhan-cau-cua-troi-sinh-than-nhan","name":"Nhãn cầu của trời sinh thần nhân","cn":"","category":"khac","categoryLabel":"Thần vật","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Được Thạch Hạo sử dụng","blurb":"Một nhãn cầu thần dị có thể được kích hoạt bằng tinh khí thần để quan sát những điều mắt thường không thấy. Thạch Hạo dùng nó giám định chiếc Chén Hóa Thiên hàng nhái.","detail":"Thạch Hạo đặt nhãn cầu trong một Động Thiên ở داخل cơ thể rồi rót tinh khí thần, khiến nó khôi phục sinh cơ và phát huy năng lực quan sát tương tự Trùng Đồng. Nhờ đó, nó nhìn thấy thần hà và vật liệu mang thần tính ẩn sâu trong chiếc chén sứ vỡ.","nguon":["@c0294"]},{"id":"chen-nho-phat-sang","name":"Chén nhỏ phát sáng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chưa rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang được sử dụng","blurb":"Chiếc chén phát sáng có khả năng thu giữ sinh vật và ép thân thể mục tiêu thu nhỏ.","detail":"Thạch Hạo lấy chiếc chén từ lòng bàn tay để thu Bích Ma Hắc Đồng Chu đang nằm trên mặt đất. Khi bị hút vào, con nhện nhanh chóng thu nhỏ còn khoảng một tấc, chìm xuống đáy chén và không thể cử động.","nguon":["@c0295"]},{"id":"thai-co-ngu-doc","name":"Thái Cổ Ngũ Độc","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Dược liệu luyện thần dược","soHuu":[],"trangThai":"Được dùng làm dược liệu","blurb":"Năm loại độc vật gồm bò cạp, nhện, rắn, rết và cóc, được dùng làm nguyên liệu chế thuốc và luyện thần dược.","detail":"Thạch Hạo xác định Bích Ma Hắc Đồng Chu bị bắt là một thành viên của Thái Cổ Ngũ Độc và có thể dùng làm vị thuốc chính khi luyện thần dược. Những độc vật này từng là các cấm kỵ Ma Thần trong thời đại xa xưa.","nguon":["@c0295"]},{"id":"chen-su-tran-ap-ma-chu","name":"Chén sứ trấn áp Ma Chu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"Đang giam giữ Ma Chu","blurb":"Chiếc chén sứ có phù văn bí lực tự động áp chế Ma Chu, khiến sinh linh bên trong không thể thoát dù miệng chén không phong kín.","detail":"Phù văn trong chén tự động thu giữ và áp chế Ma Chu dưới đáy. Khi Thạch Hạo thúc động, chén có thể sinh ra sức mạnh luyện hóa sinh linh bị giam bên trong.","nguon":["@c0296"]},{"id":"ma-chu-bi-tran-ap","name":"Ma Chu bị trấn áp","cn":"","category":"nguyen-lieu","categoryLabel":"Dược liệu sống","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang bị giam giữ","blurb":"Môn nhân của hồ Ma Linh bị Thạch Hạo trấn áp và giữ làm tù binh. Thiên Hồ tiên tử cho rằng có thể dùng sinh linh này làm chủ dược để luyện thần dược.","detail":"Thạch Hạo chỉ đồng ý không giết Ma Chu, nhưng kiên quyết không thả và cũng từ chối giao cho Thiên Hồ tiên tử. Do mối thù với hồ Ma Linh đã khó hóa giải, nó quyết định tự giữ sinh linh này làm chủ dược.","nguon":["@c0298"]},{"id":"bat-diet-kim-than","name":"Bất Diệt Kim Thân","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thạch Hạo"],"trangThai":"Đang được sử dụng","blurb":"Bảo cụ hình người màu đen có thể dung hợp với cơ thể Thạch Hạo và tăng mạnh sức chiến đấu.","detail":"Bất Diệt Kim Thân có hình dạng một người tí hon màu đen. Khi dung nhập cơ thể Thạch Hạo, nó khiến toàn thân cậu phủ ánh đen kim loại, chiến lực tăng nhiều lần và đủ sức nhanh chóng chém đầu năm kẻ tham gia sát cục tại khách sạn Hổ Môn.","nguon":["@c0299"]},{"id":"quat-bon-mau","name":"Quạt bốn màu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Văn sĩ trung niên áo xanh ngọc"],"trangThai":"Đã bị phá hủy","blurb":"Bảo cụ phóng ra ánh sáng bốn màu và lượng lớn phù văn để công kích đối thủ.","detail":"Văn sĩ trung niên áo xanh ngọc sử dụng cây quạt này trong trận phục kích Thạch Hạo. Nó được phỏng theo một Thánh Khí cùng loại thời Thượng Cổ nhưng uy lực không thể sánh bằng nguyên bản, sau đó bị linh thân Côn Bằng đánh nổ.","nguon":["@c0299"]},{"id":"thanh-dong-chien-xa-cua-lieu-han","name":"Thanh đồng chiến xa của Liễu Hàn","cn":"","category":"khac","categoryLabel":"Chiến xa","phamCap":"Không rõ","soHuu":["Liễu Hàn"],"trangThai":"Đã được trả lại bên ngoài khách sạn Hổ Môn","blurb":"Chiến xa bằng thanh đồng thuộc nhóm Liễu Hàn, được Thạch Hạo tạm thời trưng dụng làm phương tiện di chuyển.","detail":"Thạch Hạo trưng dụng chiến xa để đi từ Thanh Lâm viên tới khách sạn Hổ Môn. Sau khi đến nơi, cậu để nó bên ngoài khách sạn cho chủ nhân tự tới lấy.","nguon":["@c0299"]},{"id":"nam-hop-qua-chua-dau-nguoi","name":"Năm hộp quà chứa đầu người","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":[],"trangThai":"Đã được chuyển tới hai vương phủ","blurb":"Năm hộp quà nặng và có phù văn lấp lánh, mỗi hộp chứa thủ cấp của một kẻ tham gia mai phục Thạch Hạo.","detail":"Thạch Hạo sai người chuẩn bị các hộp quà tinh xảo rồi đặt một thủ cấp vào mỗi hộp. Người của khách sạn Hổ Môn chuyển bốn hộp tới Võ Vương phủ và một hộp tới Vũ Vương phủ mà không biết vật chứa bên trong.","nguon":["@c0299"]},{"id":"ma-dao-mau-den","name":"Ma đao màu đen","cn":"","category":"phap-bao","categoryLabel":"Bảo cụ","phamCap":"","soHuu":["Tuấn kiệt trẻ tuổi Vũ tộc cầm ma đao"],"trangThai":"Đã vỡ nát","blurb":"Bảo cụ màu đen có thể phát ra đao mang và phù văn công kích, được một tuấn kiệt Vũ tộc dùng để đối phó Thạch Hạo.","detail":"Ma đao va chạm với lôi điện của Thạch Hạo rồi bị chưởng đao đánh cho rung động, rạn nứt và cuối cùng vỡ nát.","nguon":["@c0300"]},{"id":"nguoi-ti-hon-mau-den","name":"Người tí hon màu đen","cn":"","category":"khac","categoryLabel":"Vật phẩm tăng cường","phamCap":"","soHuu":["Thạch Hạo"],"trangThai":"Đang được sử dụng","blurb":"Vật phẩm hình người nhỏ màu đen được Thạch Hạo dung hợp vào thân thể để tăng mạnh chiến lực.","detail":"Khi hợp nhất với vật phẩm này, toàn thân Thạch Hạo phát ra ánh đen, thực lực từ Hóa Linh cảnh tăng vọt và đạt chiến lực cấp Minh Văn cảnh.","nguon":["@c0300"]}]};